def _has_value(value):
    """Return whether the supplied value contains usable data."""
    if value is None:
        return False
    try:
        if value != value:
            return False
    except Exception:
        pass
    text = str(value).strip().lower()
    return text not in ("", "none", "nan", "<na>")

def _normalize_boundary_text(value):
    """Helper for the comm_cost workflow."""
    return str(value).lower().replace("_", " ").replace("-", " ").replace("/", " ")

def _row_value(row, key):
    """Read one field from a row-like object with a safe default."""
    if hasattr(row, "get"):
        return row.get(key, None)
    try:
        return row[key]
    except Exception:
        return None

def all_reduce_time(all_reduce_size,hw,all_reduce_gpu_num):
    """
    Estimate all-reduce latency for the selected hardware allreduce algorithm.
    Ring uses 2*(p-1) phases; summa/tree use 2*log2(p) phases; all2all charges pairwise fanout bytes.
    """
    return _native_cost.all_reduce_time(all_reduce_size, hw, all_reduce_gpu_num)

def ring_attention_q_transfer_bytes(gpu_batch, gpu_head, gpu_hidden, gpu_q_seq, act_bpe, cp):
    """
    Per-GPU Q traffic for context-parallel ring attention.
    KV stays sharded on its owner GPU; Q visits the other CP ranks.
    """
    return _native_cost.ring_attention_q_transfer_bytes(gpu_batch, gpu_head, gpu_hidden, gpu_q_seq, act_bpe, cp)

def ring_attention_q_transfer_time_ns(gpu_batch, gpu_head, gpu_hidden, gpu_q_seq, act_bpe, hw, cp):
    """Return ring-attention Q transfer time and transport metadata."""
    return _native_cost.ring_attention_q_transfer_time_ns(gpu_batch, gpu_head, gpu_hidden, gpu_q_seq, act_bpe, hw, cp)

def comm_bandwidth_Bps(bandwidth_GBps):
    """Convert decimal GB/s to bytes/s while avoiding division by zero."""
    return max(float(bandwidth_GBps), 1e-12) * BYTES_PER_GB

def comm_transfer_time_ns(byte_count, bandwidth_GBps, latency_ns=0.0, messages=1):
    """
    Return transfer time in ns for byte_count over a GB/s link plus per-message latency.
    Formula: bytes / (GBps * 1e9) * 1e9 + latency_ns * messages.
    """
    return float(byte_count) / comm_bandwidth_Bps(bandwidth_GBps) * 1e9 + float(messages) * float(latency_ns)

def comm_transfer_time_s(byte_count, bandwidth_GBps, latency_ns=0.0, messages=1):
    """Return transfer time in seconds using the same bandwidth-plus-latency model as comm_transfer_time_ns."""
    return comm_transfer_time_ns(byte_count, bandwidth_GBps, latency_ns, messages) / 1e9

def mesh_gpc_sources(hw, active_die, active_par, active_gpc):
    """Return one partition mesh coordinate per active GPC source."""
    return _native_cost.mesh_gpc_sources(hw, active_die, active_par, active_gpc)

def mesh_partition_coords(hw):
    """Map each hardware partition to the global partition mesh coordinate."""
    return _native_cost.mesh_partition_coords(hw)

def _is_nonempty_cell(value):
    """Return a boolean classification for the supplied value or row."""
    if value is None:
        return False
    try:
        if pd.isna(value):
            return False
    except TypeError:
        pass
    return str(value).strip() != ""

def conv_gemm_shape(op_type, ich, och, kh, kw, group, expert):
    """
    Map Conv/GEMM metadata into per-group GEMM M/K/E dimensions.
    Formula for grouped/depthwise Conv: K = (c_in / group) * kh * kw, M = c_out / group, E = group.
    """
    m, k, e, is_depthwise = _native_cost.conv_gemm_shape(op_type, ich, och, kh, kw, group, expert)
    if m < 0:
        raise ValueError(f"Invalid grouped conv: c_in={ich}, c_out={och}, group={group}")
    return ConvGemmShape(m=m, k=k, e=e, is_depthwise=is_depthwise)

def full_nn_process(hw,llm_data,is_decode,ModelArgs,gpu_sys_map,global_config,logger):
    return _native_cost.full_nn_process(
        hw,
        llm_data,
        is_decode,
        ModelArgs,
        gpu_sys_map,
        global_config,
        logger,
    )

def run_full_nn_task(args):
    """Top-level worker wrapper so tasks are picklable for multiprocessing.

    args: tuple(hw, llm_data, is_decode, ModelArgs, gpu_sys_map, GlobalConfig, logger, task_id)
    """
    hw, llm_data, is_decode, ModelArgs, gpu_sys_map, GlobalConfig, logger, task_id = args
    # Mark task as running (best-effort; ignore failures here)
    try:
        set_task_status(task_id, "running")
    except Exception:
        pass
    try:
        full_nn_process(hw, llm_data, is_decode, ModelArgs, gpu_sys_map,GlobalConfig,logger)
        try:
            set_task_status(task_id, "done")
        except Exception:
            pass
        return True
    except Exception as e:
        logger.exception("Error running full_nn_process in worker: %s", e)
        try:
            set_task_status(task_id, "failed", {"error": str(e)})
        except Exception:
            pass
        return False

def summarize_llm_timing(llm_data, ModelArgs, gpu_sys_map, global_config, hw, batch, h, w):
    """Aggregate per-layer timings through the native C++ summary model."""
    return _native_cost.summarize_llm_timing(llm_data, ModelArgs, gpu_sys_map, global_config, hw, batch, h, w)

def default_parallel_workers(cpu_count=None):
    """Return a safe default worker count for local parallel sweeps."""
    count = os.cpu_count() if cpu_count is None else cpu_count
    try:
        count = int(count)
    except (TypeError, ValueError):
        count = 1
    return max(1, count - 2)

def __init__(self):
        """Initialize GPUWorkMapper state."""
        self.gpu_work_map: List[Dict] = []
        self._factors_cache: Dict[int, List[int]] = {}
        self._combinations_cache: Dict[Tuple, List[Tuple]] = {}

def generate_4d_combinations(self, max_vals: Tuple[int, int, int, int], 
                                   product_val: int) -> List[Tuple[int, int, int, int]]:
        """生成4个因子的所有组合，满足约束且乘积等于product_val"""
        cache_key = (max_vals, product_val)
        if cache_key in self._combinations_cache:
            return self._combinations_cache[cache_key]

        max_die, max_par, max_gpc, max_sm = max_vals
        results = []
        factors = self.get_factors(product_val)

        # 提前剪枝：如果product_val大于所有最大值乘积，直接返回空
        if product_val > max_die * max_par * max_gpc * max_sm:
            self._combinations_cache[cache_key] = results
            return results

        for die in factors:
            if die > max_die:
                continue

            remaining1 = product_val // die
            for par in self.get_factors(remaining1):
                if par > max_par:
                    continue

                remaining2 = remaining1 // par
                for gpc in self.get_factors(remaining2):
                    if gpc > max_gpc:
                        continue

                    sm = remaining2 // gpc
                    if sm <= max_sm:
                        results.append((die, par, gpc, sm))

        self._combinations_cache[cache_key] = results
        return results

def get_factors(self, n: int) -> List[int]:
        """获取n的所有因子，带缓存优化"""

        factors = set()
        for i in range(1, int(math.sqrt(n)) + 1):
            if n % i == 0:
                factors.add(i)
                factors.add(n // i)

        sorted_factors = sorted(factors)

        return sorted_factors

def _coerce_gpu_info_cell(value):
    if value is None:
        return value
    try:
        if value != value:
            return value
    except TypeError:
        pass
    if not isinstance(value, str):
        return value
    text = value.strip()
    if not text:
        return value
    lowered = text.lower()
    if lowered == "true":
        return True
    if lowered == "false":
        return False
    try:
        return float(text)
    except ValueError:
        return value

def _default_gpu_info_path():
    csv_path = Path(resolve_data_file("gpu_info.csv"))
    if csv_path.exists():
        return csv_path
    return Path(resolve_data_file("gpu_info.xlsx"))

def _gpu_info_value(df, row_name, gpu_name, default):
    try:
        value = df.loc[row_name][gpu_name]
    except KeyError:
        return default
    try:
        if pd.isna(value):
            return default
    except TypeError:
        pass
    return value

def _read_gpu_info_table(path):
    source = Path(path)
    if source.suffix.lower() == ".csv":
        df = pd.read_csv(source)
    else:
        df = pd.read_excel(source)
    df.columns = df.columns.astype(str).str.strip()
    if "name" not in df.columns and len(df.columns) > 0:
        df = df.rename(columns={df.columns[0]: "name"})
    for column in df.columns:
        if column != "name":
            df[column] = df[column].map(_coerce_gpu_info_cell)
    return df.set_index('name')

def _gen_sys_work_map(self):

        # multi gpu system level tiling configs -------------------------------------
        """Generate legal PP/DP/TP/CP system maps for attention and DP/TP/EP maps for FFN."""
        range_list = []
        i = 1
        while(i<=self.gpu_num):
            range_list.append(i)
            i = i*8
        # force empty list
        self.sys_work_map = []
        # system level tiling search space
        pp_range_list      = getattr(GlobalConfig, "pp_range_list", [1])
        attn_dp_range_list = [self.gpu_num,self.gpu_num//2,self.gpu_num//4,self.gpu_num//8]
        attn_tp_range_list = GlobalConfig.attn_tp_range_list
        attn_cp_range_list = getattr(GlobalConfig, "attn_cp_range_list", [1])
        ffn_dp_range_list  = [1]
        ffn_ep_range_list  = [self.gpu_num,self.gpu_num//2,self.gpu_num//4,self.gpu_num//8]
        ffn_tp_range_list  = GlobalConfig.ffn_tp_range_list

        self.sys_work_map = []
        for pp in pp_range_list:
            for attn_dp in attn_dp_range_list:
                for attn_tp in attn_tp_range_list:
                    for attn_cp in attn_cp_range_list:
                        if(pp*attn_dp*attn_tp*attn_cp==self.gpu_num):
                            for ffn_dp in ffn_dp_range_list:
                                for ffn_tp in ffn_tp_range_list:
                                    for ffn_ep in ffn_ep_range_list:
                                        if(pp*ffn_dp*ffn_tp*ffn_ep==self.gpu_num):
                                            #logging.info('attn_pp:%d attn_dp:%d attn_tp:%d attn_cp:%d',pp,attn_dp,attn_tp,attn_cp)
                                            #logging.info('ffn_pp:%d ffn_dp:%d ffn_tp:%d ffn_ep:%d',pp,ffn_dp,ffn_tp,ffn_ep)
                                            self.sys_work_map.append({'pp':pp,'attn_dp':attn_dp,'attn_tp':attn_tp,'attn_cp':attn_cp,'attn_ep':1,'ffn_dp':ffn_dp,'ffn_tp':ffn_tp,'ffn_ep':ffn_ep})
        # force use
        if(GlobalConfig.force_sys_map):
            self.sys_work_map= GlobalConfig.sys_map
            #self.sys_work_map = [{'pp':1,'attn_dp':16,'attn_tp':2,'attn_ep':1,'ffn_dp':1,'ffn_tp':1 ,'ffn_ep':32}]
        logging.info(self.sys_work_map)
        logging.info("sys map length %d",len(self.sys_work_map))

def load_gpu_info_table(path=None):
    """Load and cache the GPU info table, preferring CSV when available."""
    return _read_gpu_info_table(_default_gpu_info_path() if path is None else path)

def resolve_gpu_info_name(gpu_name):
    """Return the canonical gpu_info column name while accepting legacy names."""
    return GPU_INFO_NAME_ALIASES.get(str(gpu_name).strip(), gpu_name)

def _analysis_for_row(row: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "mode": "single_row_with_layer_multiplier",
        "layer_count": max(int(row.get("layer", 1) or 1), 1),
        "note": "Cost model evaluates this row once and applies the row layer multiplier.",
    }

def _architecture_attention_profile(source: Mapping[str, Any], model: Mapping[str, Any]) -> dict[str, Any] | None:
    """Extract optional HF architecture attention metadata for graph row expansion."""
    arch = source.get("hf_architecture") if isinstance(source, Mapping) else None
    if not isinstance(arch, Mapping):
        return None

    config = arch.get("config") if isinstance(arch.get("config"), Mapping) else {}
    summary = arch.get("summary") if isinstance(arch.get("summary"), Mapping) else {}
    groups = arch.get("merged_layer_groups") if isinstance(arch.get("merged_layer_groups"), list) else []
    schedule = arch.get("layer_schedule") if isinstance(arch.get("layer_schedule"), list) else []
    model_key = _architecture_model_key(
        arch.get("model_type"),
        config.get("model_type"),
        source.get("model_type"),
        arch.get("model_id"),
        source.get("model"),
        model.get("model_name"),
    )
    csa_indexer_kv_source = "whole" if model_key in {"deepseek_v32", "deepseek_v3_2"} else "compressed"

    counts = {"hca": 0, "csa": 0, "kda": 0, "mla": 0, "sliding": 0}
    rates = {"hca": 128, "csa": 4, "sliding": _int_from_mapping(config, ["sliding_window"], 0)}
    for group in groups:
        if not isinstance(group, Mapping):
            continue
        kind = _attention_kind(group.get("attention_type"))
        if kind in counts:
            counts[kind] += int(group.get("layer_count") or 0)
            if group.get("compress_rate") is not None:
                rates[kind] = int(group.get("compress_rate") or rates.get(kind, 0))

    if not any(counts.values()) and schedule:
        for item in schedule:
            if not isinstance(item, Mapping):
                continue
            kind = _attention_kind(item.get("attention_type"))
            if kind in counts:
                counts[kind] += 1
                if item.get("compress_rate") is not None:
                    rates[kind] = int(item.get("compress_rate") or rates.get(kind, 0))

    for key, kind in (
        ("hca_layers", "hca"),
        ("csa_layers", "csa"),
        ("kda_layers", "kda"),
        ("linear_attention_layers", "kda"),
        ("mla_layers", "mla"),
        ("sliding_layers", "sliding"),
    ):
        if summary.get(key) is not None and counts[kind] == 0:
            counts[kind] = int(summary.get(key) or 0)

    total_layers = int(model["layers"])
    explicit = sum(counts.values())
    if explicit == 0:
        return None
    if counts["mla"] == 0 and counts["kda"] > 0 and explicit < total_layers:
        counts["mla"] = total_layers - explicit

    return {
        "counts": counts,
        "rates": rates,
        "model_key": model_key,
        "config": dict(config),
        "csa_indexer_kv_source": csa_indexer_kv_source,
        "dsa_indexer": model_key in {"deepseek_v32", "deepseek_v3_2"}
        and _int_from_mapping(config, ["index_topk", "num_index_topk"], 0) > 0,
        "mhc_streams": _int_from_mapping(config, ["hc_mult", "mhc_streams"], 0),
        "index_topk": _int_from_mapping(config, ["index_topk", "num_index_topk"], 0),
        "index_head_dim": _int_from_mapping(config, ["index_head_dim"], 0),
        "index_n_heads": _int_from_mapping(config, ["index_n_heads", "index_num_heads"], 0),
        "sliding_window": _int_from_mapping(config, ["sliding_window"], 0),
        "linear_state_dim": _int_from_mapping(config, ["linear_state_dim", "state_dim", "kda_state_dim"], int(model["v_head_dim"])),
        "linear_chunk_size": _int_from_mapping(config, ["linear_chunk_size", "chunk_size", "kda_chunk_size"], 64),
    }

def _architecture_model_key(*values: Any) -> str:
    for value in values:
        text = str(value or "").strip().lower()
        if text:
            return re.sub(r"[^a-z0-9]+", "_", text).strip("_")
    return ""

def _attention_kind(attention_type: Any) -> str:
    text = str(attention_type or "").strip().lower()
    if text in {"heavily_compressed_attention", "hca"}:
        return "hca"
    if text in {"compressed_sparse_attention", "csa"}:
        return "csa"
    if text in {"kda", "linear_attention", "linear", "delta_attention", "deltanet"}:
        return "kda"
    if text in {"mla", "global_mla", "global_attention", "self_attention"}:
        return "mla"
    if text in {"sliding_attention", "sliding_window"}:
        return "sliding"
    return text

def _bool_value(source: Any, name: str, default: bool = False) -> bool:
    """Read one field and coerce it to bool with a safe default."""
    value = _value(source, name, default)
    if isinstance(value, str):
        return value.strip().lower() in {"1", "true", "yes", "y"}
    return bool(value)

def _bpe_for_precision(precision: str, default: float) -> float:
    """Return storage bytes per element for known precision tokens."""
    normalized = _precision_text(precision)
    if normalized in {"fp4", "nvfp4"}:
        return 0.5
    if normalized == "fp8":
        return 1.0
    if normalized in {"bf16", "fp16"}:
        return 2.0
    if normalized == "fp32":
        return 4.0
    return float(default)

def add(row: Mapping[str, Any], tags: list[str] | None = None) -> None:
        """Append one cost-model node and connect it to the previous node."""
        _append_node(nodes, used_ids, phase, row, tags=tags)

def _compute_precision_for_operands(feature_precision: str, weight_precision: str, default: str) -> str:
    """Resolve mixed GEMM operands to the tensorcore precision selector."""
    ranks = {"fp4": 0, "nvfp4": 0, "fp8": 1, "bf16": 2, "fp16": 2, "fp32": 3}
    feature = _precision_text(feature_precision)
    weight = _precision_text(weight_precision)
    rank = max(ranks.get(feature, -1), ranks.get(weight, -1))
    if rank >= 3:
        return "fp32"
    if rank >= 2:
        return "fp16"
    if rank == 1:
        return "fp8"
    if rank == 0:
        return "fp4"
    return _precision_text(default)

def _edges_for(nodes: list[Mapping[str, Any]]) -> list[dict[str, str]]:
    """Build sequential data-flow edges between ordered graph nodes."""
    return [
        {"source": str(nodes[index]["id"]), "target": str(nodes[index + 1]["id"]), "kind": "data"}
        for index in range(len(nodes) - 1)
    ]

