def _effective_kv_seq(base_kv_seq: int, kind: str, profile: Mapping[str, Any]) -> int:
    rates = profile.get("rates", {})
    sliding_window = int(profile.get("sliding_window", 0) or 0)
    if kind == "hca":
        rate = max(int(rates.get("hca", 128) or 128), 1)
        return max(1, ceil(base_kv_seq / rate))
    if kind == "csa":
        rate = max(int(rates.get("csa", 4) or 4), 1)
        compressed = ceil(base_kv_seq / rate)
        index_topk = int(profile.get("index_topk", 0) or 0)
        if index_topk > 0:
            compressed = min(compressed, index_topk)
        return max(1, compressed)
    if kind == "mla" and bool(profile.get("dsa_indexer", False)):
        index_topk = int(profile.get("index_topk", 0) or 0)
        if index_topk > 0:
            return max(1, min(base_kv_seq, index_topk))
    if kind == "sliding" and sliding_window > 0:
        return max(1, min(base_kv_seq, sliding_window))
    return max(1, base_kv_seq)

def _effective_weight_bpe(weight_precision: str, scale_group: int | float, scale_bpe: int | float, default: float) -> float:
    """Include per-group quantization scale storage in effective weight bytes."""
    base_bpe = _bpe_for_precision(weight_precision, default)
    if _precision_text(weight_precision) == "nvfp4" and float(scale_group or 0) > 0:
        return base_bpe + float(scale_bpe or 0) / float(scale_group)
    return base_bpe

def _equation_for_raw_node(name: str, op: str, attrs: Mapping[str, Any] | None = None) -> dict[str, str]:
    attrs = attrs or {}
    role = str(attrs.get("role", ""))
    if role == "qk_score":
        return {
            "plain": "QK computes attention scores before masking and softmax.",
            "latex": "S=QK^T/sqrt(d)",
        }
    if role == "attention_softmax":
        return {
            "plain": "Attention softmax normalizes causal scores over the key sequence.",
            "latex": "P=softmax(S+M)",
        }
    if role == "score_value":
        return {
            "plain": "SV multiplies normalized attention probabilities by values.",
            "latex": "O=PV",
        }
    return {
        "plain": f"{name} raw {op} operation.",
        "latex": f"Y={op}(X)",
    }

def _equation_for_row(row: Mapping[str, Any]) -> dict[str, str]:
    op_type = str(row.get("type", ""))
    name = str(row.get("NN name", ""))
    token = row.get("token", "T")
    c_in = row.get("c_in", "C_in")
    c_out = row.get("c_out", "C_out")
    q_head = row.get("q_head", "H_q")
    kv_head = row.get("kv_head", "H_kv")
    layer = row.get("layer", "L")

    if op_type == "MHA":
        return {
            "plain": "Attn(Q,K,V) = softmax(Q K^T / sqrt(d) + mask) V. With attn_cp > 1, KV is sharded by sequence and Q moves around the CP ring.",
            "latex": (
                "Attn(Q,K,V)=softmax((QK^T)/sqrt(d)+M)V; "
                f"T_q={token}, T_kv={c_in}, H_q={q_head}, H_kv={kv_head}, repeat={layer}; "
                "local T_kv = ceil(T_kv/CP)"
            ),
        }
    if op_type == "MatMul":
        if name.lower() == "router":
            return {
                "plain": "router_logits = X W_router; experts = topk(softmax(router_logits)).",
                "latex": f"R=XW_router, topk(softmax(R)); X in R^({token}x{c_in}), W in R^({c_in}x{c_out})",
            }
        return {
            "plain": "Y = X W.",
            "latex": f"Y=XW; X in R^({token}x{c_in}), W in R^({c_in}x{c_out})",
        }
    if op_type == "Softmax":
        return {
            "plain": "softmax(z_i) = exp(z_i) / sum_j exp(z_j).",
            "latex": "softmax(z_i)=exp(z_i)/sum_j exp(z_j)",
        }
    if op_type == "RMS Norm":
        return {
            "plain": "RMSNorm(x) = x * gamma / sqrt(mean(x^2) + eps).",
            "latex": "RMSNorm(x)=x*gamma/sqrt(mean(x^2)+eps)",
        }
    if op_type == "Rope":
        return {
            "plain": "RoPE rotates query/key pairs with position-dependent sin/cos phases.",
            "latex": "[x_0',x_1']=[x_0 cos theta - x_1 sin theta, x_0 sin theta + x_1 cos theta]",
        }
    if op_type == "emb":
        return {
            "plain": "X = Embedding[token_ids].",
            "latex": "X=E[token_ids]",
        }
    if op_type == "Add":
        return {
            "plain": "Y = A + B.",
            "latex": "Y=A+B",
        }
    if op_type == "Mul":
        return {
            "plain": "Y = A * B.",
            "latex": "Y=A dot B",
        }
    if op_type.lower() in {"silu", "gelu", "relu"}:
        return {
            "plain": f"{op_type}(x) activation.",
            "latex": f"Y={op_type}(X)",
        }
    return {
        "plain": f"{op_type} operation.",
        "latex": f"Y={op_type}(X)",
    }

def _find_raw_attention_ids(raw_graph: Mapping[str, Any]) -> list[str]:
    """Helper for the llm_graph workflow."""
    roles = {"qk_score", "attention_softmax", "score_value"}
    by_role: dict[str, str] = {}
    for node in raw_graph.get("nodes", []):
        attrs = node.get("attrs", {})
        role = attrs.get("role")
        if role in roles:
            by_role[str(role)] = str(node["id"])
    ordered_roles = ["qk_score", "attention_softmax", "score_value"]
    return [by_role[role] for role in ordered_roles if role in by_role]

def _find_raw_attention_ids_by_source(raw_graph: Mapping[str, Any]) -> dict[str, list[str]]:
    """Return raw QK/softmax/SV ids grouped by their fused cost MHA source row."""
    roles = {"qk_score", "attention_softmax", "score_value"}
    grouped: dict[str, dict[str, str]] = {}
    for node in raw_graph.get("nodes", []):
        attrs = node.get("attrs", {})
        role = attrs.get("role")
        source_cost_node = attrs.get("source_cost_node")
        if role in roles and source_cost_node:
            grouped.setdefault(str(source_cost_node), {})[str(role)] = str(node["id"])

    ordered_roles = ["qk_score", "attention_softmax", "score_value"]
    return {
        source_id: [by_role[role] for role in ordered_roles if role in by_role]
        for source_id, by_role in grouped.items()
    }

def _float_value(source: Any, name: str, default: float = 1.0) -> float:
    """Read one field and coerce it to float with a safe default."""
    value = _value(source, name, default)
    if value is None:
        return float(default)
    return float(value)

def _ids_with_any_tag(nodes: list[Mapping[str, Any]], tags: set[str]) -> list[str]:
    result: list[str] = []
    for node in nodes:
        node_tags = set(str(tag) for tag in node.get("tags", []))
        if node_tags & tags:
            result.append(str(node["id"]))
    return result

def _int_from_mapping(source: Mapping[str, Any], keys: list[str], default: int = 0) -> int:
    for key in keys:
        value = source.get(key)
        if value is not None:
            try:
                return int(value)
            except (TypeError, ValueError):
                return default
    return default

def _int_value(source: Any, name: str, default: int = 0) -> int:
    """Read one field and coerce it to int with a safe default."""
    value = _value(source, name, default)
    if value is None:
        return int(default)
    return int(value)

def _is_attention_projection_matmul(op_type: str, component: str, weight_en: int | float) -> bool:
    """Classify the attention projection GEMMs that have static weights."""
    return (
        str(op_type) == "MatMul"
        and str(component) == "attention_projection"
        and float(weight_en or 0) != 0.0
    )

def _phase_graph(nodes: list[dict[str, Any]]) -> dict[str, Any]:
    """Helper for the llm_graph workflow."""
    return {"nodes": nodes, "edges": _edges_for(nodes)}

def _repeat_for_row(row: Mapping[str, Any]) -> dict[str, Any]:
    count = max(int(row.get("layer", 1) or 1), 1)
    return {
        "axis": "layer",
        "count": count,
        "draw": "single_node",
    }

def _transformer_layer_equation(model: Mapping[str, Any]) -> dict[str, str]:
    layers = int(model["layers"])
    dense_layers = int(model["dense_layers"])
    sparse_layers = max(layers - dense_layers, 0)
    return {
        "plain": (
            "For each transformer layer: a = x + Attn(RMSNorm(x)); "
            "y = a + FFN_or_MoE(RMSNorm(a)). Dense MLP is used for early dense layers; "
            "routed MoE is used for sparse layers."
        ),
        "latex": (
            "a_l=x_l+Attn(Q,K,V), Attn(Q,K,V)=softmax((QK^T)/sqrt(d)+M)V; "
            "x_{l+1}=a_l+FFN_or_MoE(RMSNorm(a_l)); "
            f"L={layers}, dense={dense_layers}, sparse={sparse_layers}"
        ),
    }

def _value(source: Any, name: str, default: Any = None) -> Any:
    """Read one field from a row-like object with a safe default."""
    if isinstance(source, Mapping):
        return source.get(name, default)
    return getattr(source, name, default)

def build_llm_graph(spec: Any, source: Mapping[str, Any] | None = None, optimize: bool = False) -> dict[str, Any]:
    """Build cost and raw graph representations from a normalized model spec."""
    model = _model_dict_from_spec(spec)
    source_dict = dict(source or {})
    source_dict.setdefault("model_type", source_dict.get("model_type", model["model_name"]))
    source_dict.setdefault("code_files", [])
    source_dict.setdefault("warnings", [])

    raw_graphs = {
        "prefill": _phase_graph(_build_raw_phase_nodes(model, "prefill", source=source_dict)),
        "decode": _phase_graph(_build_raw_phase_nodes(model, "decode", source=source_dict)),
    }
    cost_graphs = merge_raw_graphs_to_cost_graphs(model, raw_graphs, source=source_dict)
    layer_templates = {
        phase: _build_layer_template_graph(model, phase, cost_graph)
        for phase, cost_graph in cost_graphs.items()
    }
    graph = {
        "schema_version": SCHEMA_VERSION,
        "model": model,
        "source": source_dict,
        "raw_graphs": raw_graphs,
        "cost_graphs": cost_graphs,
        "layer_templates": layer_templates,
        "compact_graphs": layer_templates,
        "graphs": cost_graphs,
        "optimizations": [],
    }
    if optimize:
        graph = optimize_llm_graph(graph)
    return graph

def graph_to_layer_tables(graph: Mapping[str, Any]):
    """Helper for the llm_graph workflow."""
    return graph_to_layer_dataframe(graph, "prefill"), graph_to_layer_dataframe(graph, "decode")

def merge_raw_graph_to_cost_graph(
    model: Mapping[str, Any],
    phase: str,
    raw_graph: Mapping[str, Any],
    source: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    """Merge raw traced attention subgraphs into the fused cost-model MHA node."""
    cost_nodes = _build_cost_phase_nodes(model, phase, source=source)
    raw_attention_by_source = _find_raw_attention_ids_by_source(raw_graph)
    fallback_raw_attention_ids = _find_raw_attention_ids(raw_graph)
    for node in cost_nodes:
        raw_attention_ids = raw_attention_by_source.get(str(node["id"]), fallback_raw_attention_ids)
        if node["op"] == "MHA" and raw_attention_ids:
            node["merge"] = {
                "pass": "merge_attention_subgraph",
                "raw_node_ids": raw_attention_ids,
                "reason": "cost model estimates attention with one fused MHA macro node",
            }
    return _phase_graph(cost_nodes)

def merge_raw_graphs_to_cost_graphs(
    model: Mapping[str, Any],
    raw_graphs: Mapping[str, Mapping[str, Any]],
    source: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    """Merge every raw phase graph into its cost-model macro graph."""
    return {
        phase: merge_raw_graph_to_cost_graph(model, phase, raw_graph, source=source)
        for phase, raw_graph in raw_graphs.items()
    }

def optimize_llm_graph(graph: Mapping[str, Any]) -> dict[str, Any]:
    """Return an optimized graph copy after applying graph-level simplifications."""
    optimized = copy.deepcopy(dict(graph))
    optimized.setdefault("optimizations", []).append(
        {
            "name": "stable_topological_order",
            "description": "Preserves cost-model-visible nodes while recording deterministic graph order.",
        }
    )
    for graph_key in ("raw_graphs", "cost_graphs", "layer_templates"):
        for phase_graph in optimized.get(graph_key, {}).values():
            phase_graph["nodes"] = sorted(phase_graph.get("nodes", []), key=lambda node: int(node.get("order", 0)))
            phase_graph["edges"] = _edges_for(phase_graph["nodes"])
    optimized["compact_graphs"] = optimized.get("layer_templates", optimized.get("compact_graphs", {}))
    optimized["graphs"] = optimized.get("cost_graphs", optimized.get("graphs", {}))
    for phase_graph in optimized.get("graphs", {}).values():
        phase_graph["nodes"] = sorted(phase_graph.get("nodes", []), key=lambda node: int(node.get("order", 0)))
        phase_graph["edges"] = _edges_for(phase_graph["nodes"])
    return optimized

def __init__(self):
        """Initialize LoggerFactory state."""
        self._handlers = {}

def cleanup(self):
        """程序退出时清理所有句柄"""
        for name, handler in self._handlers.items():
            handler.close()
