def _load_state() -> Dict[str, Any]:
    """Load the full task state from disk.

    Returns an empty dict if the file does not exist or is invalid.
    """
    if not os.path.exists(_STATE_FILE):
        return {}
    try:
        with open(_STATE_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            return data
    except Exception:
        # Corrupted file or race; ignore and start fresh for safety.
        pass
    return {}

def get_task_status(task_id: str) -> Optional[str]:
    """Return the status string for the given task_id, or None if unknown."""
    if not task_id:
        return None
    with _lock:
        state = _load_state()
        entry = state.get(task_id)
        if isinstance(entry, dict):
            return entry.get("status")  # type: ignore[return-value]
        if isinstance(entry, str):
            # Backwards compatibility if we ever stored plain strings.
            return entry
        return None

def _row_int(nn_info, line: int, column: str, default: int = 0) -> int:
    """Read an int field from a graph row, treating zero as missing when a non-zero default is supplied."""
    try:
        value = int(float(_row_value(nn_info, line, column, default)))
    except (TypeError, ValueError):
        return int(default)
    if value == 0 and int(default) != 0:
        return int(default)
    return value

def _row_text(nn_info, line: int, column: str, default: str = "") -> str:
