def _row_value(nn_info, line: int, column: str, default: Any = 0) -> Any:
    if column not in nn_info.columns:
        return default
    value = nn_info.loc[line, column]
    try:
        if value != value:
            return default
    except TypeError:
        pass
    return default if value is None else value

def _largest_fit_tile(limit, stride, capacity):
    """Return the largest stride-aligned tile that fits both the requested limit and capacity."""
    stride = max(int(stride), 1)
    limit = int(limit)
    if limit <= 0 or capacity <= 0:
        return 0
    if capacity >= limit:
        return limit
    return int(floor(capacity / stride) * stride)

def _tile_candidates(limit, stride):
    """Return aligned tile candidates up to limit, always including the exact limit."""
    stride = max(int(stride), 1)
    limit = int(limit)
    if limit <= 0:
        return []
    values = list(range(stride, limit + 1, stride))
    if not values or values[-1] != limit:
        values.append(limit)
    return values

def _tile_candidates(limit, stride, preferred, dense_limit=1024):
    """Return exact small tile ranges and sampled large ranges."""
    if limit <= 0:
        return []
    max_tile = ceil(limit / stride) * stride
    candidate_count = max_tile // stride
    if candidate_count <= dense_limit:
        return list(range(stride, max_tile + stride, stride))

    candidates = {stride, max_tile}
    for tile in preferred:
        aligned_tile = ceil(tile / stride) * stride
        if stride <= aligned_tile <= max_tile:
            candidates.add(aligned_tile)

    tile = stride
    while tile < max_tile:
        candidates.add(tile)
        tile *= 2

    return sorted(candidates)

def attr_text_optional(self, obj, name):
        if obj is None or type(obj).__module__.startswith("unittest.mock"):
