def _apply_full_nn_owned_update_application(nn_info, application):
    extra_column_count = int(application.extra_column_count)
    if extra_column_count > 0 and not bool(application.extra_column_names):
        raise RuntimeError("Native full_nn_owned_update_application returned invalid extra column names.")
    for index in range(extra_column_count):
        nn_info[_native_char_buffer_text(application.extra_column_names[index])] = ""

    op_count = int(application.op_count)
    if op_count > 0 and not bool(application.ops):
        raise RuntimeError("Native full_nn_owned_update_application returned invalid dataframe ops.")
    safe_cell_count = int(application.cell_count)
    scalar_ops = []

    def flush_scalar_ops():
        if scalar_ops:
            _apply_scalar_dataframe_write_ops_bulk(nn_info, scalar_ops)
            scalar_ops.clear()

    for index in range(op_count):
        op = application.ops[index]
        line = int(op.line)
        op_kind = int(op.op_kind)
        if op_kind == FULL_NN_DATAFRAME_WRITE_SCALAR:
            scalar_ops.append(op)
            continue

        flush_scalar_ops()
        if op_kind == FULL_NN_DATAFRAME_APPLY_ROW:
            cell_offset = int(op.cell_offset)
            value_count = int(op.cell_count)
            if cell_offset < 0 or value_count < 0 or cell_offset + value_count > safe_cell_count:
                raise RuntimeError("Native full_nn_owned_update_application returned invalid cell bounds.")
            nn_info.loc[line] = _full_nn_materialized_positional_cells_to_list(
                application.cells[cell_offset + value_index] for value_index in range(value_count)
            )
            continue

        column = _native_char_buffer_text(op.column)
        if op_kind == FULL_NN_DATAFRAME_WRITE_EMPTY_DICT:
            if column not in nn_info.columns:
                nn_info[column] = None
            nn_info.at[line, column] = {}
            continue

        if op_kind == FULL_NN_DATAFRAME_WRITE_DIRECTION_TRAFFIC:
            if column not in nn_info.columns:
                nn_info[column] = None
            current = nn_info.at[line, column]
            if not isinstance(current, dict):
                current = {}
            coord, traffic_value = _full_nn_dataframe_write_op_direction_payload(op)
            current[coord] = traffic_value
            nn_info.at[line, column] = current
            continue

        raise RuntimeError(f"Native full_nn dataframe op has unknown kind {op_kind}.")
    flush_scalar_ops()

