def _build_single_op_work_maps_from_text(gpu_work_map_text):
    lib = _require_native("single_op_work_maps_from_text")
    map_capacity = 16
    while True:
        maps = (FastSingleOpWorkMap * map_capacity)()
        map_count = ctypes.c_int()
        try:
            rc = lib.llm_cost_single_op_work_maps_from_text(
                gpu_work_map_text,
                maps,
                map_capacity,
                ctypes.byref(map_count),
            )
        except (ctypes.ArgumentError, OSError, TypeError, ValueError) as error:
            raise RuntimeError("Native single_op_work_maps_from_text call failed.") from error
        if rc == 2:
            map_capacity = max(map_capacity * 2, int(map_count.value))
            continue
        if rc != 0:
            raise RuntimeError(f"Native single_op_work_maps_from_text returned error code {rc}.")
        if map_count.value <= 0:
            return None, 0
        return maps, int(map_count.value)

def _config_entries_text(config):
    if config is None or type(config).__module__.startswith("unittest.mock"):
        return _to_native_text(())
    try:
        names = set(vars(config).keys())
    except TypeError:
        names = set()
    try:
        for name in dir(config):
            if not name.startswith("_"):
                names.add(name)
    except TypeError:
        pass
    entries = []
    for name in sorted(names):
        try:
            value = getattr(config, name)
        except Exception:
            continue
        if value is not None and type(value).__module__.startswith("unittest.mock"):
            continue
        if callable(value):
            continue
        if value is None or isinstance(value, (str, bytes, bool, numbers.Number, Enum)):
            entries.extend((_to_native_text(name), _to_native_text("" if value is None else value)))
    return _to_native_text(tuple(entries))

