def _full_nn_materialized_positional_cell_to_python(cell):
    scalar_kind = int(cell.scalar_kind)
    if scalar_kind == FULL_NN_SCALAR_BOOL:
        return bool(cell.int_value)
    if scalar_kind == FULL_NN_SCALAR_TEXT:
        return _native_char_buffer_text(cell.text_value)
    if scalar_kind == FULL_NN_SCALAR_INT:
        return int(cell.int_value)
    return float(cell.double_value)

