        return _attr_text_optional(model_args, name)
    if source == FULL_NN_ARG_SOURCE_GLOBAL:
        return _attr_text_optional(global_config, name)
    if source == FULL_NN_ARG_SOURCE_GPU_MAP:
        return _gpu_map_text(gpu_sys_map, name)
    return _attr_text_optional(hw, name)

