def _full_nn_return_entry_value(postprocess, entry):
    value_kind = int(entry.value_kind)
    if value_kind == FULL_NN_RETURN_RUN_SUMMARY:
        return _full_nn_named_scalar_values_to_dict(postprocess.run_summary_values)
    if value_kind == FULL_NN_RETURN_FINALIZE_RESULT:
        return _full_nn_return_entries_to_dict(postprocess, postprocess.finalize_entries)
    if value_kind == FULL_NN_RETURN_BATCH:
        return int(entry.int_value)
    if value_kind == FULL_NN_RETURN_SUMMARY_ROW:
        return _full_nn_summary_row_values_to_list(postprocess.summary_row_values)
    if value_kind == FULL_NN_RETURN_LAYOUT:
        return _full_nn_named_scalar_values_to_dict(postprocess.layout_values)
    if value_kind == FULL_NN_RETURN_WORKBOOK_META:
        return _full_nn_named_scalar_values_to_dict(postprocess.workbook_meta_values)
    if value_kind == FULL_NN_RETURN_NATIVE_RESULT:
        return postprocess.finalize_result
    raise RuntimeError(f"Native full_nn return entry has unknown value kind {value_kind}.")

