def _full_nn_update_array(updates):
    if updates is None:
        update_count = 0
    else:
        update_count = len(updates)
    array_type = FastFullNnCellUpdate * max(update_count, 1)
    if update_count <= 0:
        return array_type(), 0
    if isinstance(updates, ctypes.Array):
        return updates, update_count
    return array_type(*updates), update_count

def _full_nn_update_array_with_count(updates, update_count):
    update_count = int(update_count)
    array_type = FastFullNnCellUpdate * max(update_count, 1)
    if update_count <= 0:
        return array_type(), 0
    if isinstance(updates, ctypes.Array):
        source_count = len(updates)
        if update_count > source_count:
            raise IndexError("Full NN cell update count exceeds source update array length.")
        return updates, update_count
    if not bool(updates):
        raise IndexError("Full NN cell update pointer is null.")
    return ctypes.cast(updates, ctypes.POINTER(array_type)).contents, update_count

def _full_nn_workbook_column_value_lists(values):
    if isinstance(values, pd.DataFrame):
        return (
            [[None, *values.index.tolist()]]
            + [[column, *values[column].tolist()] for column in values.columns]
        )
    return [[cell.value for cell in column_cells] for column_cells in values]

