    return values

def _has_value(value):
    if value is None:
        return False
    try:
        if value != value:
            return False
    except Exception:
        pass
    text = str(value).strip().lower()
    return text not in ("", "none", "nan", "<na>")

def _hw_noc_result_from_dict(result, fallback_min_time):
    out = FastHwNocRunResult()
    for name, c_type in FastHwNocRunResult._fields_:
        if name == "hbm_capacity_ok":
            default = True
        elif name in {"min_time", "op_time"}:
            default = fallback_min_time
        else:
            default = 0
        value = result.get(name, default) if isinstance(result, dict) else default
        if name in {"is_better_config", "early_break", "hbm_capacity_ok"}:
            setattr(out, name, 1 if value else 0)
        elif c_type is ctypes.c_int:
            setattr(out, name, int(value))
        else:
            setattr(out, name, float(value))
    return out

