            if name in {"is_better_config", "early_break", "hbm_capacity_ok"}
            else int(getattr(out, name))
            if c_type is ctypes.c_int
            else float(getattr(out, name))
        )
        for name, c_type in FastHwNocRunResult._fields_
    }
    if partition_direction_traffic is not None:
        result["partition_direction_traffic"] = partition_direction_traffic
    return result

