    raise NativeLoadError("unable to load native cost model helper shared library")

def _native_text_buffer(function_name, *args, capacity=512):
    lib = _require_native(function_name)
    buffer = ctypes.create_string_buffer(capacity)
    try:
        rc = getattr(lib, function_name)(*args, buffer, capacity)
    except (ctypes.ArgumentError, OSError, TypeError, ValueError) as error:
        raise RuntimeError(f"Native {function_name} call failed.") from error
    if rc != 0:
        raise RuntimeError(f"Native {function_name} returned error code {rc}.")
    return buffer.value.decode("utf-8")

def _need_rebuild(lib_path: Path) -> bool:
    if not lib_path.exists():
