        return "pp boundary only allowed at transformer/mtp module boundary"
    return ""

def _raise_full_nn_process_apply_error(result, hw):
    if result.error_kind == FULL_NN_APPLY_ERROR_DEPTHWISE:
        raise ValueError(_full_nn_depthwise_error_message(hw))
    if result.error_kind == FULL_NN_APPLY_ERROR_ZERO_DIVISION:
        raise ZeroDivisionError("float division by zero")
    if result.error_kind == FULL_NN_APPLY_ERROR_RUNTIME:
        raise RuntimeError(f"Native full_nn_process_apply returned error code {int(result.error_code)}.")

def _require_native(function_name: str) -> ctypes.CDLL:
    if _NATIVE_LIB is None:
        raise RuntimeError(
            f"Native C++ helper for {function_name} is unavailable. "
            "Rebuild/load the native extension before running this operation."
        )
    return _NATIVE_LIB

def _row_bytes(row, name):
    try:
        value = row.get(name, "")
    except AttributeError:
        value = ""
    if value is None:
        return b""
    try:
        if pd.isna(value):
            return b""
    except (TypeError, ValueError):
        pass
    return str(value).encode("utf-8")

def _row_field(row, key, default=None):
    try:
        return row.get(key, default)
    except AttributeError:
        pass
    try:
        return row[key]
    except Exception:
        return default

def _row_optional_int(row, name):
    try:
        value = row.get(name, None)
    except AttributeError:
        return _MISSING_ROW_INT
    if value is None:
        return _MISSING_ROW_INT
    try:
        if pd.isna(value):
            return _MISSING_ROW_INT
    except (TypeError, ValueError):
        pass
    try:
        return int(float(value))
    except (TypeError, ValueError):
        return _MISSING_ROW_INT

def _row_text_value(row, name):
