    return str(value)

def _run_full_nn_process_postprocess_owned_result(llm_data, result):
    application = _full_nn_owned_postprocess_application(result, llm_data.columns)
    try:
        postprocess = application.postprocess
        for index in range(int(postprocess.postprocess_actions.action_count)):
            action_kind = int(postprocess.postprocess_actions.actions[index].action_kind)
            if action_kind == FULL_NN_POSTPROCESS_APPLY_UPDATES:
                _apply_full_nn_owned_update_application(llm_data, application.update_application)
                continue
            if action_kind == FULL_NN_POSTPROCESS_WRITE_WORKBOOK:
                write_full_nn_result_workbook(llm_data, postprocess.workbook_write_plan)
                continue
            if action_kind == FULL_NN_POSTPROCESS_RETURN_RESULT:
                return _full_nn_owned_postprocess_return_to_dict(postprocess)
            raise RuntimeError(f"Native full_nn postprocess action has unknown kind {action_kind}.")
        raise RuntimeError("Native full_nn postprocess action list did not include a return action.")
    finally:
        _free_full_nn_owned_postprocess_application(application)

def _single_op_batch_item_value(item, name, default=None):
