        return item.get(name, default)
    return getattr(item, name, default)

def _source_fragment_paths() -> list[Path]:
    if not _SOURCE.exists():
        return []
    marker = '#include "cost_model_fast/'
    fragments: list[Path] = []
    for line in _SOURCE.read_text(encoding="utf-8").splitlines():
        if marker not in line:
            continue
        include_name = line.split(marker, 1)[1].split('"', 1)[0]
        if include_name.endswith(".cpp"):
            fragments.append(_SOURCE_PARTS_DIR / include_name)
    return fragments

def _text_column(frame, column, default=""):
    if column in frame.columns:
        return [str(value) if value is not None else default for value in frame[column].fillna(default).tolist()]
    return [default] * len(frame)

def _to_native_text(value):
