        )
    except (ctypes.ArgumentError, OSError, TypeError) as error:
        raise RuntimeError("Native all_reduce_time call failed.") from error
    if result < 0:
        raise AssertionError("all reduce type not supported")
    return result

def apply_full_nn_cell_update_buffer(nn_info, updates, update_count):
