    try:
        _apply_full_nn_owned_update_application(nn_info, application)
    finally:
        _free_full_nn_owned_update_application(application)

def apply_full_nn_cell_updates(nn_info, updates):
    update_array, update_count = _full_nn_update_array(updates)
    apply_full_nn_cell_update_buffer(nn_info, update_array, update_count)

def available() -> bool:
    """Whether the optional native extension is loaded and usable."""
    return _NATIVE_LIB is not None

def conv_gemm_shape(op_type, ich, och, kh, kw, group, expert):
    lib = _require_native("conv_gemm_shape")
    if isinstance(op_type, str):
        op_type_b = op_type.encode("utf-8")
    elif op_type is None:
        op_type_b = None
    else:
        op_type_b = bytes(op_type)

    try:
        shape = lib.llm_cost_conv_gemm_shape(
            op_type_b,
            int(ich),
            int(och),
            int(kh),
            int(kw),
            int(group),
            int(expert),
        )
    except (ctypes.ArgumentError, OSError, TypeError) as error:
        raise RuntimeError("Native conv_gemm_shape call failed.") from error

    return (
        int(shape.m),
        int(shape.k),
        int(shape.e),
        bool(shape.is_depthwise),
    )

def full_nn_initial_update_capacity(line_count, header_count):
    lib = _require_native("full_nn_initial_update_capacity")
    try:
