def single_op_full_process_apply_cells_native(*, native_result, nn_info, line, hw, dp, tp, ep, pp):
    lib = _require_native("single_op_full_process_apply_cells_native")
    row = nn_info.loc[line]
    result = FastSingleOpOwnedApplyCellsResult()
    try:
        rc = lib.llm_cost_single_op_full_process_apply_cells_owned_result(
            ctypes.byref(native_result),
            _row_bytes(row, "gpu_comm"),
            int(line),
            int(dp),
            int(tp),
            int(ep),
            int(pp),
            ctypes.byref(result),
        )
    except (ctypes.ArgumentError, OSError, TypeError, ValueError) as error:
        raise RuntimeError("Native single_op_full_process_apply_cells call failed.") from error
    try:
        if result.error_kind == SINGLE_OP_APPLY_ERROR_GEMM_TILING:
            raise AssertionError("no GEMM sm tiling fit found")
        if result.error_kind == SINGLE_OP_APPLY_ERROR_ATTENTION_TILING:
            raise AssertionError("no fit flashing attention tiling found")
        if result.error_kind == SINGLE_OP_APPLY_ERROR_RUNTIME:
            raise RuntimeError(
                f"Native single_op_full_process_apply_cells returned error code {int(result.error_code)}."
            )

        apply_full_nn_cell_update_buffer(nn_info, result.updates, result.update_count)
        if result.summary.depthwise_unsupported:
            raise ValueError(_full_nn_depthwise_error_message(hw))
        return bool(result.early_break)
    finally:
        _free_full_nn_owned_apply_result_updates(result)

def single_op_full_process_cell_updates_native(*, native_result, nn_info, line, hw, dp, tp, ep, pp):
    """Return copied native cell updates without mutating the DataFrame."""
    lib = _require_native("single_op_full_process_apply_cells_native")
    row = nn_info.loc[line]
    result = FastSingleOpOwnedApplyCellsResult()
    try:
        rc = lib.llm_cost_single_op_full_process_apply_cells_owned_result(
            ctypes.byref(native_result),
            _row_bytes(row, "gpu_comm"),
            int(line),
            int(dp),
            int(tp),
            int(ep),
            int(pp),
            ctypes.byref(result),
        )
    except (ctypes.ArgumentError, OSError, TypeError, ValueError) as error:
        raise RuntimeError("Native single_op_full_process_apply_cells call failed.") from error
    try:
        if result.error_kind == SINGLE_OP_APPLY_ERROR_GEMM_TILING:
            raise AssertionError("no GEMM sm tiling fit found")
        if result.error_kind == SINGLE_OP_APPLY_ERROR_ATTENTION_TILING:
            raise AssertionError("no fit flashing attention tiling found")
        if result.error_kind == SINGLE_OP_APPLY_ERROR_RUNTIME:
            raise RuntimeError(
                f"Native single_op_full_process_apply_cells returned error code {int(result.error_code)}."
            )

        update_count = int(result.update_count)
        if update_count > 0 and not bool(result.updates):
            raise RuntimeError("Native single_op_full_process_apply_cells returned invalid update pointer.")
        updates = [
            _copy_ctypes_struct(FastFullNnCellUpdate, result.updates[index])
            for index in range(update_count)
        ]
        summary = _copy_ctypes_struct(FastFullNnApplyCellSummary, result.summary)
        return updates, bool(result.early_break), summary
    finally:
        _free_full_nn_owned_apply_result_updates(result)

