def _default_report_model_name(report: Mapping[str, Any], config: Mapping[str, Any]) -> str | None:
    model_id = report.get("model_id")
    if model_id:
        return str(model_id)
    name = config.get("_name_or_path") or config.get("name_or_path") or config.get("model_type")
    return str(name) if name else None

def _dict_payload(report: Mapping[str, Any], key: str) -> dict[str, Any]:
    value = report.get(key) or {}
    return dict(value) if isinstance(value, Mapping) else {}

def _list_payload(report: Mapping[str, Any], key: str) -> list[Any]:
    value = report.get(key) or []
    return list(value) if isinstance(value, list) else []

def architecture_report_config(report: Mapping[str, Any]) -> dict[str, Any]:
    """Return the merged config payload used for cost-model normalization."""
    raw = report.get("raw_config") or report.get("config") or {}
    normalized = report.get("normalized_config") or {}
    if not isinstance(raw, Mapping):
        raw = {}
    if not isinstance(normalized, Mapping):
        normalized = {}

    def merge_payload(payload: Mapping[str, Any]) -> dict[str, Any]:
        merged = dict(payload)
        text_config = payload.get("text_config")
        if isinstance(text_config, Mapping):
            merged.update({key: value for key, value in text_config.items() if value is not None})
        return merged

    config = merge_payload(raw)
    config.update({key: value for key, value in merge_payload(normalized).items() if value is not None})
    return config

def merge_payload(payload: Mapping[str, Any]) -> dict[str, Any]:
        merged = dict(payload)
        text_config = payload.get("text_config")
        if isinstance(text_config, Mapping):
            merged.update({key: value for key, value in text_config.items() if value is not None})
        return merged

def load_architecture_report(path: str | Path) -> dict[str, Any]:
    """Load an HF architecture report JSON produced by hf_arch_exporter.py."""
    report_path = Path(path)
    report = json.loads(report_path.read_text(encoding="utf-8"))
    if not isinstance(report, dict):
        raise ValueError(f"HF architecture report must be a JSON object: {report_path}")
    if not any(key in report for key in ("config", "raw_config", "normalized_config")):
        raise ValueError(f"HF architecture report has no config payload: {report_path}")
    return report

def _get(config: Any, name: str, default: Any = None) -> Any:
    """Return a normalized value or lookup result for the caller."""
    if isinstance(config, dict):
        return config.get(name, default)
    return getattr(config, name, default)

def _has(config: Any, name: str) -> bool:
    """Return whether the supplied value contains usable data."""
    if isinstance(config, dict):
        return name in config
    return hasattr(config, name)

def _set(config: Any, name: str, value: Any) -> None:
    """Store a normalized value for later use."""
    if isinstance(config, dict):
        config[name] = value
        return
    setattr(config, name, value)

def summarize_fx_graph(
    graph_module: Any,
    *,
    repo: str,
    trace_kind: str,
    input_shape: list[int],
    output_shape: list[int] | None,
) -> dict[str, Any]:
    """Summarize raw model data into compact metrics."""
    node_records = []
    for index, node in enumerate(graph_module.graph.nodes):
        shape, dtype = _node_tensor_meta(node)
        node_records.append(
            {
                "index": index,
                "op": node.op,
                "target": str(node.target),
                "shape": shape,
                "dtype": dtype,
            }
        )

    counts = Counter(record["target"] for record in node_records if record["op"] == "call_function")
    interesting = {
        key: value
        for key, value in sorted(counts.items())
        if any(token in key for token in INTERESTING_ATEN_TOKENS)
    }
    return {
        "status": "ok",
        "repo": repo,
        "trace_kind": trace_kind,
        "input_shape": input_shape,
        "output_shape": output_shape,
        "node_count": len(node_records),
        "interesting_call_counts": interesting,
        "first_120_nodes": node_records[:120],
    }

