def _collect_hub_code_files(model: str) -> tuple[list[dict[str, Any]], list[str]]:
    """Helper for the hf_to_llmperf_graph workflow."""
    warnings: list[str] = []
    try:
        from huggingface_hub import hf_hub_download, list_repo_files
    except ImportError:
        return [], ["huggingface_hub is not installed; skipped remote model code summary"]

    try:
        repo_files = list_repo_files(model)
    except Exception as exc:  # pragma: no cover - network and auth dependent
        return [], [f"failed to list HuggingFace repo files for {model}: {exc}"]

    code_files: list[dict[str, Any]] = []
    for repo_file in sorted(repo_files):
        if not _is_code_file(repo_file):
            continue
        try:
            downloaded = Path(hf_hub_download(model, repo_file))
            code_files.append(_summarize_python_code(downloaded, display_path=repo_file))
        except Exception as exc:  # pragma: no cover - network and auth dependent
            warnings.append(f"failed to download {repo_file}: {exc}")
    return code_files, warnings

def _collect_local_code_files(model_path: Path) -> list[dict[str, Any]]:
    """Helper for the hf_to_llmperf_graph workflow."""
    files: list[dict[str, Any]] = []
    for path in sorted(model_path.rglob("*.py")):
        relative = path.relative_to(model_path).as_posix()
        if path.is_file() and _is_code_file(relative):
            files.append(_summarize_python_code(path, display_path=relative))
    return files

def _is_code_file(path: str) -> bool:
    """Return a boolean classification for the supplied value or row."""
    normalized = path.replace("\\", "/")
    name = Path(path).name
    return any(fnmatch.fnmatch(name, pattern) or fnmatch.fnmatch(normalized, pattern) for pattern in CODE_PATTERNS)

def _source_model_type(config: Any) -> str:
    """Helper for the hf_to_llmperf_graph workflow."""
    return str(_get(config, "model_type", "_name_or_path", default="unknown"))

def _summarize_python_code(path: Path, display_path: str | None = None) -> dict[str, Any]:
    """Helper for the hf_to_llmperf_graph workflow."""
    text = path.read_text(encoding="utf-8")
    digest = hashlib.sha256(text.encode("utf-8")).hexdigest()
    classes: list[str] = []
    functions: list[str] = []
    try:
        tree = ast.parse(text)
    except SyntaxError:
        tree = None
    if tree is not None:
        for node in tree.body:
            if isinstance(node, ast.ClassDef):
                classes.append(node.name)
            elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                functions.append(node.name)
    return {
        "path": display_path or str(path),
        "sha256": digest,
        "bytes": len(text.encode("utf-8")),
        "classes": classes,
        "functions": functions,
    }

