def _attention_weight_precision_from_model_precision(precision: str) -> str:
    """Default attention weights to NVFP4 when the model precision requests fp4."""
    normalized = _precision_text(precision)
    if normalized == "fp4":
        return "nvfp4"
    return normalized

def _default_model_name(model: str, config: Any) -> str:
    """Helper for the hf_to_llmperf_xlsx workflow."""
    model_path = Path(model)
    if model_path.exists():
        return model_path.name
    configured_name = _get(config, "_name_or_path", "name_or_path")
    if configured_name:
        return str(configured_name)
    if "/" in model:
        return model
    return str(_get(config, "model_type", default=model))

def _excel_value(value: Any) -> Any:
    """Coerce pandas/numpy scalars into plain Python values for openpyxl."""
    if hasattr(value, "item"):
        try:
            return value.item()
        except Exception:
            return value
    return value

def _get(config: Any, *names: str, default: Any = None) -> Any:
    """Return a normalized value or lookup result for the caller."""
    for name in names:
        if isinstance(config, Mapping) and name in config:
            value = config[name]
        else:
            value = getattr(config, name, None)
        if value is not None:
            return value
    return default

def _model_name(config: Any, explicit: str | None) -> str:
    """Resolve the output model name from an explicit override or config metadata."""
    if explicit:
        return explicit
    name = _get(config, "_name_or_path", "name_or_path", "model_type", default="Unknown")
    return str(name) if name else "Unknown"

def _required_int(config: Any, field_name: str, *names: str) -> int:
    """Read a required integer config field from one of several HF aliases."""
    value = _get(config, *names)
    if value is None:
        aliases = ", ".join(names)
        raise ValueError(f"Missing required {field_name}; checked: {aliases}")
    return int(value)

def _scale_bpe_for_weight_precision(weight_precision: str, scale_group: int, explicit_bpe: float | None) -> float:
    """Default NVFP4 scale storage to one byte per scale value."""
    if explicit_bpe is not None:
        return float(explicit_bpe)
    return 1.0 if _precision_text(weight_precision) == "nvfp4" and scale_group > 0 else 0.0

def _scale_group_for_weight_precision(weight_precision: str, explicit_group: int | None) -> int:
    """Default NVFP4 weights to one scale value per eight weight elements."""
    if explicit_group is not None:
        return int(explicit_group)
    return 8 if _precision_text(weight_precision) == "nvfp4" else 0

def _write_layer_sheet(sheet: Worksheet, layer_rows: list[Mapping[str, Any]]) -> None:
    """Write one phase layer table with a single header row."""
    for col_idx, column_name in enumerate(LLM_LAYER_COLUMNS, start=1):
        sheet.cell(row=1, column=col_idx, value=column_name)
    for row_idx, row in enumerate(layer_rows, start=2):
        for col_idx, column_name in enumerate(LLM_LAYER_COLUMNS, start=1):
            sheet.cell(row=row_idx, column=col_idx, value=_excel_value(row.get(column_name, 0)))
    sheet.freeze_panes = "A2"
    for col_idx, column_name in enumerate(LLM_LAYER_COLUMNS, start=1):
        width = max(min(len(str(column_name)) + 2, 28), 10)
        sheet.column_dimensions[sheet.cell(row=1, column=col_idx).column_letter].width = width

