def load_transformers_config(model: str, trust_remote_code: bool = False) -> Any:
    """Load persisted input data for this workflow."""
    def load_config_json() -> Any:
        """Load persisted input data for this workflow."""
        config_path = Path(model) / "config.json"
        if config_path.exists():
            return json.loads(config_path.read_text(encoding="utf-8"))
        try:
            from huggingface_hub import hf_hub_download
        except ImportError as exc:
            raise RuntimeError(
                "transformers could not load this model; install huggingface_hub or provide a local config.json"
            ) from exc
        downloaded = hf_hub_download(model, "config.json")
        return json.loads(Path(downloaded).read_text(encoding="utf-8"))

    try:
        from transformers import AutoConfig
    except ImportError as exc:
        try:
            return load_config_json()
