def resolve_call(self, raw_name: str | None) -> str | None:
        """Resolve a local reference into a concrete target."""
        if not raw_name:
            return None
        parts = raw_name.split(".")
        first = parts[0]

        if first in {"self", "cls"} and len(parts) >= 2:
            class_name = class_name_for_function(self.current_function, self.module_name)
            method_id = self.class_methods.get((class_name or "", parts[1]))
            if method_id:
                return method_id

        if len(parts) == 1 and raw_name in self.module_local_names:
            return self.module_local_names[raw_name]

        if first in self.imports:
            candidate = ".".join([self.imports[first], *parts[1:]])
            if candidate in self.known_function_ids:
                return candidate
            return candidate

        candidate = f"{self.module_name}.{raw_name}"
        if candidate in self.known_function_ids:
            return candidate
        if raw_name in self.known_function_ids:
            return raw_name
        return None

def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef) -> None:
        """AST visitor hook for this node type."""
        return

def visit_Call(self, node: ast.Call) -> None:
        """AST visitor hook for this node type."""
        raw_name = dotted_name(node.func)
        resolved = self.resolve_call(raw_name)
        if resolved and resolved in self.known_function_ids:
            self.calls.append(resolved)
        elif raw_name:
            self.external_calls.append(raw_name)
        self.generic_visit(node)

def visit_ClassDef(self, node: ast.ClassDef) -> None:
        """AST visitor hook for this node type."""
        return

def visit_FunctionDef(self, node: ast.FunctionDef) -> None:
        """AST visitor hook for this node type."""
        return

def visit_AnnAssign(self, node: ast.AnnAssign) -> None:
    """AST visitor hook for this node type."""
    if node.value is None:
      return
    target_text = extract_source_segment(self.source_text, node.target)
    self._maybe_add(target_text, node.value, node)

def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef) -> None:
    """AST visitor hook for this node type."""
    return

def visit_ClassDef(self, node: ast.ClassDef) -> None:
    """AST visitor hook for this node type."""
    return

def visit_FunctionDef(self, node: ast.FunctionDef) -> None:
    """AST visitor hook for this node type."""
    return

def visit_Return(self, node: ast.Return) -> None:
    """AST visitor hook for this node type."""
    if node.value is None:
      return
    if isinstance(node.value, ast.Dict):
      for key, value in zip(node.value.keys, node.value.values):
        if key is None or value is None:
          continue
        if isinstance(key, ast.Constant) and isinstance(key.value, str):
          target_text = key.value
        else:
          target_text = extract_source_segment(self.source_text, key)
        self._maybe_add(target_text, value, value)
      return
    self._maybe_add("return", node.value, node)

def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef) -> None:
        """AST visitor hook for this node type."""
        self._record_function(node)

def visit_FunctionDef(self, node: ast.FunctionDef) -> None:
        """AST visitor hook for this node type."""
        self._record_function(node)

def visit_Attribute(self, node: ast.Attribute) -> None:
      """AST visitor hook for this node type."""
      name = dotted_name(node)
      if name:
        symbols.add(name)
      if not isinstance(node.value, ast.Name):
        self.visit(node.value)

def visit_Name(self, node: ast.Name) -> None:
      """AST visitor hook for this node type."""
      symbols.add(node.id)

def collect_expression_symbols(expr: ast.AST) -> list[str]:
  """Collect variable and attribute names referenced by one formula expression."""
  symbols: set[str] = set()

  class SymbolCollector(ast.NodeVisitor):
    def visit_Attribute(self, node: ast.Attribute) -> None:
      """AST visitor hook for this node type."""
      name = dotted_name(node)
      if name:
        symbols.add(name)
      if not isinstance(node.value, ast.Name):
        self.visit(node.value)

    def visit_Name(self, node: ast.Name) -> None:
      """AST visitor hook for this node type."""
      symbols.add(node.id)

  SymbolCollector().visit(expr)
  filtered = []
  for symbol in sorted(symbols):
    if symbol in IGNORED_SYMBOLS:
      continue
    if leaf_name(symbol) in IGNORED_SYMBOLS:
      continue
    filtered.append(symbol)
  return filtered

def collect_imports(tree: ast.AST, module_name: str) -> dict[str, str]:
    """Collect source or AST metadata for downstream processing."""
    imports: dict[str, str] = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                local = alias.asname or alias.name.split(".")[0]
                imports[local] = alias.name
        elif isinstance(node, ast.ImportFrom):
            base = resolve_relative_module(module_name, node.module, node.level)
            for alias in node.names:
                if alias.name == "*":
                    continue
                local = alias.asname or alias.name
                imports[local] = f"{base}.{alias.name}" if base else alias.name
    return imports

def collect_parameters(node: ast.FunctionDef | ast.AsyncFunctionDef) -> list[str]:
  """Collect user-visible function parameters, excluding self and cls."""
  parameters: list[str] = []
  all_args = list(getattr(node.args, "posonlyargs", [])) + list(node.args.args) + list(node.args.kwonlyargs)
  for arg in all_args:
    if arg.arg not in {"self", "cls"}:
      parameters.append(arg.arg)
  if node.args.vararg:
    parameters.append(f"*{node.args.vararg.arg}")
  if node.args.kwarg:
    parameters.append(f"**{node.args.kwarg.arg}")
  return parameters

def default_formula_explanation(target: str, expression_text: str, kind: str, symbols: list[str]) -> str:
  """Generate a concise explanation for formulas that do not have a curated description."""
  compact = re.sub(r"\s+", "", expression_text)
  target_name = friendly_target(target)
  if kind == "alignment":
    return f"{target_name} 通过 `ceil(x / tile) * tile` 形式向上对齐到硬件 tile，避免后续 kernel 出现不整除。"
  if "comm_transfer_time_s" in compact or "comm_transfer_time_ns" in compact:
    return f"{target_name} 由传输字节数除以链路带宽，再叠加每条消息的固定延迟得到。"
  if "/hw.freq" in compact:
    return f"{target_name} 把周期数或 FLOPs 对应的 tile 次数除以核心频率，换算成时间。"
  if "sum(" in compact and "**" in compact:
    return f"{target_name} 是一个几何级数求和，用来表示多 stage 或多 offset 的累计期望收益。"
  if kind == "volume":
    return f"{target_name} 主要通过把相关维度相乘得到总规模，通常表示字节数、元素数或 FLOPs。"
  if kind == "time":
    return f"{target_name} 是时间/时延公式，用工作量除以频率或带宽，再结合必要的固定开销换算得到。"
  if kind == "rate":
    return f"{target_name} 表示吞吐或速率，通常由收益与总时间共同决定。"
  if kind == "partition":
    return f"{target_name} 表示离散切分后的份额，通常会配合 `ceil`/`max` 保证至少切出一个合法分块。"
  if symbols:
    return f"{target_name} 由 {', '.join(symbols[:5])} 等变量组合计算得到。"
  return f"{target_name} 是该函数里的关键中间量。"

def default_function_summary(info: FunctionInfo, docstring: str, formulas: list[dict], callees: list[str]) -> str:
  """Build the fallback function summary displayed in the call graph page."""
  if docstring:
    return docstring.strip().splitlines()[0]
  if info.module.startswith("llm_perf.kernels"):
    prefix = "这是一个 kernel/SM 级建模函数"
  elif info.module.startswith("llm_perf.comm"):
    prefix = "这是一个通信或 NoC 建模函数"
  elif info.module.startswith("llm_perf.core"):
    prefix = "这是一个核心调度或硬件配置函数"
  elif info.module.startswith("scripts"):
    prefix = "这是一个脚本入口或可视化辅助函数"
  else:
    prefix = "这是一个仓库内函数"
  return f"{prefix}，提取到 {len(formulas)} 条关键计算公式，并直接关联 {len(callees)} 个仓库内函数。"

def describe_symbol(symbol: str) -> str:
  """Return a short human-readable description."""
  return VARIABLE_GLOSSARY.get(symbol) or VARIABLE_GLOSSARY.get(leaf_name(symbol)) or "代码里的中间变量或配置项"

def dotted_name(node: ast.AST) -> str | None:
    """Return a dotted symbol name extracted from an AST node."""
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        base = dotted_name(node.value)
        if base:
            return f"{base}.{node.attr}"
    return None

def explain_formula(function_id: str, target: str, expression_text: str, kind: str, symbols: list[str]) -> str:
  """Return a curated formula note when available, otherwise a generated one."""
  guide = FUNCTION_GUIDES.get(function_id, {})
  notes = guide.get("formula_notes", {})
  if target in notes:
    return notes[target]
  if target == "return" and "return" in notes:
    return notes["return"]
  return default_formula_explanation(target, expression_text, kind, symbols)

def extract_formula_entries(function_id: str, node: ast.AST, source_text: str) -> list[dict]:
  """Extract formula-like assignments and returns from one function AST node."""
  collector = FormulaCollector(function_id, source_text)
  for statement in getattr(node, "body", []):
    collector.visit(statement)
  return collector.entries

def extract_source_segment(source_text: str, node: ast.AST) -> str:
  """Return the exact source text represented by an AST node."""
  segment = ast.get_source_segment(source_text, node)
  if segment:
    return segment.rstrip()
  lines = source_text.splitlines()
  start = max(int(getattr(node, "lineno", 1)) - 1, 0)
  end = int(getattr(node, "end_lineno", getattr(node, "lineno", 1)))
  return "\n".join(lines[start:end]).rstrip()

def flatten_expression_terms(expr: ast.AST, source_text: str, operator_type: type[ast.operator]) -> list[str]:
  """Flatten a multiplication or addition expression into displayable terms."""
  def _flatten(node: ast.AST) -> list[ast.AST]:
    """Recursively flatten the selected binary operator."""
    if isinstance(node, ast.BinOp) and isinstance(node.op, operator_type):
      return _flatten(node.left) + _flatten(node.right)
    return [node]

  if not isinstance(expr, ast.BinOp) or not isinstance(expr.op, operator_type):
    return []
  terms = []
  for part in _flatten(expr):
    terms.append(extract_source_segment(source_text, part))
  return terms

def _flatten(node: ast.AST) -> list[ast.AST]:
    """Recursively flatten the selected binary operator."""
    if isinstance(node, ast.BinOp) and isinstance(node.op, operator_type):
      return _flatten(node.left) + _flatten(node.right)
    return [node]

def formula_kind(target: str, expression_text: str) -> str:
  """Classify a formula as time, volume, rate, partitioning, or generic math."""
  target_lower = target.lower()
  compact = re.sub(r"\s+", "", expression_text)
  if "time" in target_lower or "latency" in target_lower or "comm_transfer_time_" in compact:
    return "time"
  if compact.startswith("ceil(") and ")*" in compact:
    return "alignment"
  if "bytes" in target_lower or "size" in target_lower or "elements" in target_lower or "flops" in target_lower:
    return "volume"
  if "rps" in target_lower or "tps" in target_lower or "throughput" in target_lower or "speedup" in target_lower:
    return "rate"
  if "iter" in target_lower or "parallel" in target_lower or "count" in target_lower:
    return "partition"
  if "sum(" in compact and "**" in compact:
    return "series"
  return "formula"

def friendly_target(target: str) -> str:
  """Return a readable display label for a technical identifier."""
  if target == "return":
    return "返回值"
  return VARIABLE_GLOSSARY.get(target) or VARIABLE_GLOSSARY.get(leaf_name(target)) or target

def guide_steps_for(function_id: str) -> list[str]:
  """Return curated call-flow guide steps for a function id."""
  guide = FUNCTION_GUIDES.get(function_id, {})
  return list(guide.get("steps", []))

def is_formula_expression(expr: ast.AST) -> bool:
  """Return whether an AST expression looks like a cost-model formula."""
  has_math_operator = any(isinstance(child, (ast.BinOp, ast.UnaryOp, ast.Pow)) for child in ast.walk(expr))
  if has_math_operator:
    return True
  for child in ast.walk(expr):
    if isinstance(child, ast.Call):
      name = dotted_name(child.func) or ""
      if leaf_name(name) in FORMULA_CALL_NAMES:
        return True
  return False

def iter_python_files(source_roots: Iterable[Path]) -> list[Path]:
    """Return Python files under the selected roots, excluding generated/cache directories."""
    files = []
    ignored_parts = {"__pycache__", ".git", ".venv", "result"}
    for source_root in source_roots:
        source_root = Path(source_root)
        if source_root.is_file() and source_root.suffix == ".py":
            files.append(source_root)
            continue
        for path in source_root.rglob("*.py"):
            if ignored_parts.intersection(path.parts):
                continue
            files.append(path)
    return sorted(files)

def leaf_name(symbol: str) -> str:
  """Return the final component of a dotted symbol."""
  return symbol.split(".")[-1]

def module_name_for_path(path: Path, repo_root: Path) -> str:
    """Helper for the build_call_graph_page workflow."""
    relative = path.resolve().relative_to(repo_root.resolve())
    parts = list(relative.with_suffix("").parts)
    if parts[-1] == "__init__":
        parts = parts[:-1]
    return ".".join(parts)

def parse_source_files(source_roots: Iterable[Path], repo_root: Path) -> tuple[dict[str, ast.AST], dict[str, str], dict[str, str]]:
    """Parse user input or CLI text into structured values."""
    trees: dict[str, ast.AST] = {}
    modules_by_file: dict[str, str] = {}
    source_texts: dict[str, str] = {}
    for path in iter_python_files(source_roots):
        try:
            source_text = path.read_text(encoding="utf-8")
            tree = ast.parse(source_text, filename=str(path))
        except SyntaxError:
            continue
        module_name = module_name_for_path(path, repo_root)
        trees[str(path.resolve())] = tree
        modules_by_file[str(path.resolve())] = module_name
        source_texts[str(path.resolve())] = source_text
    return trees, modules_by_file, source_texts

def resolve_relative_module(current_module: str, module: str | None, level: int) -> str:
    """Resolve a local reference into a concrete target."""
    if level <= 0:
        return module or ""
    package_parts = current_module.split(".")[:-1]
    if level > 1:
        package_parts = package_parts[: -(level - 1)]
    if module:
        package_parts.extend(module.split("."))
    return ".".join(part for part in package_parts if part)

def latency_s(self) -> float:
        """Helper for the disaggregated_inference workflow."""
