def _component_sum(phase: PhaseResult, component_names: tuple[str, ...]) -> float:
    """Aggregate selected per-token component timings from a phase result."""
    components = phase.components or {}
    return sum(float(components.get(name, 0.0)) for name in component_names)

def _decode_split_config_for_phase(decode: PhaseResult, config: DecodeAttnFfnSplitConfig) -> DecodeAttnFfnSplitConfig:
    """Prepare decode-stage configuration for the caller."""
    ffn_gpu = config.ffn_gpu or decode.gpu
    bandwidth = _min_endpoint_value((decode.gpu, ffn_gpu), config.hardware_bandwidth_GBps, config.bandwidth_GBps)
    latency = _min_endpoint_value((decode.gpu, ffn_gpu), config.hardware_latency_ns, config.latency_ns)
    return replace(config, bandwidth_GBps=bandwidth, latency_ns=latency)

def _float_value(row, key: str, default: float = 0.0) -> float:
    """Read one field and coerce it to float with a safe default."""
    value = _value(row, key, default)
    if value is None or pd.isna(value):
        return default
    return float(value)

def _min_endpoint_value(gpu_names: tuple[str, str], values: dict[str, float] | None, default: float) -> float:
    """Return the most conservative configured value across the two endpoint GPU types."""
    if not values:
        return default
    endpoints = [float(values[gpu_name]) for gpu_name in gpu_names if gpu_name in values]
    return min(endpoints) if endpoints else default

def _pd_transfer_config_for_pair(
    prefill: PhaseResult,
    decode: PhaseResult,
    config: PdTransferConfig,
) -> PdTransferConfig:
    """Resolve PD transfer placement and endpoint-specific bandwidth/latency."""
    placement = str(config.placement).lower()
    if placement == "auto":
        placement = "same_node" if _phases_fit_one_node(prefill, decode, config.hardware_gpu_per_node) else "inter_node"

    if placement in ("same_node", "intra_node", "nvlink"):
        bandwidth = _min_endpoint_value(
            (prefill.gpu, decode.gpu),
            config.hardware_intra_node_bandwidth_GBps,
            config.intra_node_bandwidth_GBps,
        )
        latency = _min_endpoint_value(
            (prefill.gpu, decode.gpu),
            config.hardware_intra_node_latency_ns,
            config.intra_node_latency_ns,
        )
        return replace(
            config,
            transport=config.intra_node_transport,
            bandwidth_GBps=bandwidth,
            latency_ns=latency,
        )

    if placement not in ("inter_node", "cross_node", "cx9", "nic"):
        raise ValueError(f"unsupported pd transfer placement: {config.placement}")

    bandwidth = _min_endpoint_value((prefill.gpu, decode.gpu), config.hardware_bandwidth_GBps, config.bandwidth_GBps)
    latency = _min_endpoint_value((prefill.gpu, decode.gpu), config.hardware_latency_ns, config.latency_ns)
    return replace(config, transport=config.inter_node_transport or config.transport, bandwidth_GBps=bandwidth, latency_ns=latency)

def _phases_fit_one_node(
    prefill: PhaseResult,
    decode: PhaseResult,
    gpu_per_node_by_hw: dict[str, float] | None,
) -> bool:
    """Helper for the disaggregated_inference workflow."""
    if prefill.gpu != decode.gpu or not gpu_per_node_by_hw or prefill.gpu not in gpu_per_node_by_hw:
        return False
    return prefill.gpu_num + decode.gpu_num <= int(gpu_per_node_by_hw[prefill.gpu])

def _value(row, key: str, default=None):
    """Read one field from a row-like object with a safe default."""
    if isinstance(row, pd.Series):
        return row[key] if key in row else default
    return row.get(key, default)

def infer_lengths_from_config_name(name: str) -> tuple[int, int]:
    """Extract input/output token lengths from an encoded result name."""
    match = re.search(r"_I(\d+)_O(\d+)", str(name))
    if not match:
        return 1, 1
    return int(match.group(1)), int(match.group(2))

