def _component_share_rows(rows: pd.DataFrame) -> pd.DataFrame:
    if rows is None or rows.empty:
        return pd.DataFrame()
    selected = rows.copy()
    available = [column for column in _COMPONENT_TIME_COLUMNS if column in selected.columns]
    if not available:
        return selected
    numeric = selected[available].apply(pd.to_numeric, errors="coerce").fillna(0.0)
    totals = numeric.sum(axis=1).replace(0.0, math.nan)
    for column in available:
        selected[f"{column} share"] = (numeric[column] / totals).fillna(0.0)
    return selected

def _derive_total_throughput(df: pd.DataFrame) -> pd.Series:
