    if {"TPS per gpu", "Gpu num"}.issubset(df.columns):
        return (
            pd.to_numeric(df["TPS per gpu"], errors="coerce").fillna(0.0)
            * pd.to_numeric(df["Gpu num"], errors="coerce").fillna(0.0)
        )
    if {"tps_per_gpu", "gpu_num"}.issubset(df.columns):
        return (
            pd.to_numeric(df["tps_per_gpu"], errors="coerce").fillna(0.0)
            * pd.to_numeric(df["gpu_num"], errors="coerce").fillna(0.0)
        )
    return pd.Series(0.0, index=df.index)

