                return parsed if parsed > 0 else default
        return default

def _load_artifact_frames(result_dir: Path, web_data_dir: Path, prefix: str | None) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    decode_path = result_dir / f"{prefix}_decode_strategy_sweep.csv" if prefix else None
    if decode_path is None or not decode_path.exists():
        decode_path = _first_existing(["*_decode_strategy_sweep.csv"], result_dir)
    overall_path = result_dir / f"{prefix}_unified_strategy_candidates.csv" if prefix else None
    if overall_path is None or not overall_path.exists():
        overall_path = _first_existing(["*_unified_strategy_candidates.csv"], result_dir)
    prefill_path = web_data_dir / "final_prefill_all.xlsx"
    return _read_csv_if_exists(decode_path), _read_xlsx_if_exists(prefill_path), _read_csv_if_exists(overall_path)

def _mtp_stage_effect_rows(decode_rows: pd.DataFrame) -> pd.DataFrame:
    if decode_rows is None or decode_rows.empty or "mtp_stage" not in decode_rows.columns:
        return pd.DataFrame(columns=["mtp_stage", "tps_per_user", "throughput_total_tps", "tps_per_gpu"])
    rows = decode_rows.copy()
    rows["mtp_stage"] = pd.to_numeric(rows["mtp_stage"], errors="coerce").fillna(0).astype(int)
    rows["tps_per_user"] = pd.to_numeric(rows.get("tps_per_user", 0.0), errors="coerce").fillna(0.0)
    rows["throughput_total_tps"] = _derive_total_throughput(rows)
    rows["tps_per_gpu"] = pd.to_numeric(rows.get("tps_per_gpu", 0.0), errors="coerce").fillna(0.0)
    rows = rows[rows["mtp_stage"].between(0, 9)]
    if rows.empty:
        return pd.DataFrame(columns=["mtp_stage", "tps_per_user", "throughput_total_tps", "tps_per_gpu"])
    ranked = rows.sort_values(["mtp_stage", "tps_per_user", "throughput_total_tps"], ascending=[True, False, False])
    return ranked.groupby("mtp_stage", as_index=False).head(1).reset_index(drop=True)

def _number(value, default: float = 0.0) -> float:
    try:
        if value is None or pd.isna(value):
            return default
    except (TypeError, ValueError):
        pass
    try:
        return float(value)
    except (TypeError, ValueError):
        return default

def _numeric_column_sum(rows: pd.DataFrame, column: str) -> float:
    if column not in rows.columns:
        return 0.0
    return float(pd.to_numeric(rows[column], errors="coerce").fillna(0.0).sum())

def _read_csv_if_exists(path: Path | None) -> pd.DataFrame:
    if path is None or not path.exists():
        return pd.DataFrame()
    return pd.read_csv(path)

def _read_xlsx_if_exists(path: Path | None) -> pd.DataFrame:
    if path is None or not path.exists():
        return pd.DataFrame()
    return pd.read_excel(path)

def _row_get(row: Mapping | pd.Series, name: str, default=None):
    if hasattr(row, "get"):
        return row.get(name, default)
    try:
        return row[name]
    except Exception:
        return default

def data_parser_with_batch(data_parser, batch_value: int):
        values = list(data_parser)
        values[9] = int(batch_value)
        return tuple(values)

def _top_rows(df: pd.DataFrame, sort_column: str, top_n: int = 5) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    rows = df.copy()
    if sort_column not in rows.columns:
        rows[sort_column] = 0.0
    rows["_rank_value"] = pd.to_numeric(rows[sort_column], errors="coerce").fillna(0.0)
    batch_col = "batch_attn_gpu" if "batch_attn_gpu" in rows.columns else "Batch" if "Batch" in rows.columns else "batch" if "batch" in rows.columns else None
    sort_columns = ["_rank_value"]
    ascending = [False]
    if batch_col is not None:
        rows["_rank_batch"] = pd.to_numeric(rows[batch_col], errors="coerce").fillna(float("inf"))
        sort_columns.append("_rank_batch")
        ascending.append(True)
    rows = rows.sort_values(sort_columns, ascending=ascending).head(top_n)
    rows = rows.drop(columns=[column for column in ("_rank_value", "_rank_batch") if column in rows.columns])
    return rows.reset_index(drop=True)

def _transport_name(value) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except (TypeError, ValueError):
        pass
    text = str(value).strip().lower()
    if text in {"", "0", "none", "nan", "<na>"}:
        return ""
    if text in {"1", "p2p", "nvlink", "intra", "intra_node", "same_node"}:
        return "p2p"
    if text in {"2", "nic", "cx", "cx9", "rdma", "inter", "inter_node", "cross_node"}:
        return "nic"
    if text in {"3", "pcie", "pci-e", "pci_e"}:
        return "pcie"
    return text

def _write_csv(path: Path, rows: pd.DataFrame) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    if rows is None or rows.empty and len(rows.columns) == 0:
        rows = pd.DataFrame([{"status": "no_rows"}])
    rows.to_csv(path, index=False)

def bottleneck_domain_scores(row: Mapping | pd.Series) -> dict[str, float]:
    """Return comparable ns-level scores for all supported bottleneck domains."""
    op_time = _number(_row_get(row, "op time"))
    scores: dict[str, float] = {}
    for domain in HARDWARE_BOTTLENECK_DOMAINS:
        percent_score = _max_numeric(row, _PERCENT_COLUMNS.get(domain, ())) * op_time
        time_score = _max_numeric(row, _TIME_COLUMNS.get(domain, ()))
        scores[domain] = max(percent_score, time_score)

    cp_time = _number(_row_get(row, "cp comm time"))
    cp_transport = _transport_name(_row_get(row, "cp comm transport"))
    if cp_time > 0.0 and cp_transport in {"pcie", "p2p", "nic"}:
        scores[cp_transport] = max(scores[cp_transport], cp_time)

    return scores

def build_selected_bottlenecks(
    *,
    workbook: Path | None,
    hardware: str,
    gpu_num: int,
    decode_mtp_off: pd.DataFrame,
    decode_mtp_on: pd.DataFrame,
    prefill_top: pd.DataFrame,
) -> pd.DataFrame:
    if workbook is None or not workbook.exists():
        return pd.DataFrame()
    pieces = []
    selections = [
        ("decode", "decode-mtp-off", decode_mtp_off),
        ("decode", "decode-mtp-on", decode_mtp_on),
        ("prefill", "prefill", prefill_top),
    ]
    for phase, label, rows in selections:
        if rows is None or rows.empty:
            continue
        for rank, (_, row) in enumerate(rows.head(5).iterrows(), start=1):
            llm_data = _run_layers_for_config(
                workbook=workbook,
                phase=phase,
                hardware=hardware,
                gpu_num=gpu_num,
                row=row,
            )
            if llm_data.empty:
                continue
            pieces.append(
                summarize_op_bottlenecks(
                    llm_data,
                    config_label=f"{label}-top{rank}",
                    phase=phase,
                )
            )
    if not pieces:
        return pd.DataFrame()
    return pd.concat(pieces, ignore_index=True)

def summarize_op_bottlenecks(
    rows: pd.DataFrame,
    *,
    config_label: str,
    phase: str | None = None,
) -> pd.DataFrame:
    """Aggregate per-layer cost-model rows into per-op bottleneck rows."""
    output_columns = [
        "phase",
        "config_label",
        "component",
        "type",
        "row_count",
        "op_time_s",
        "comm_time_s",
        "bottleneck_domain",
        *[f"{domain}_score_ns" for domain in HARDWARE_BOTTLENECK_DOMAINS],
    ]
    if rows is None or rows.empty:
        return pd.DataFrame(columns=output_columns)

    enriched = rows.copy()
    for domain in HARDWARE_BOTTLENECK_DOMAINS:
        enriched[f"{domain}_score_ns"] = enriched.apply(
            lambda row, domain=domain: bottleneck_domain_scores(row).get(domain, 0.0),
            axis=1,
        )
    if "component" not in enriched.columns:
        enriched["component"] = enriched.get("NN name", "unknown")
    if "type" not in enriched.columns:
        enriched["type"] = enriched.get("op layout", "unknown")

    pieces = []
    for (component, op_type), group in enriched.groupby(["component", "type"], dropna=False):
        score_sums = {
            f"{domain}_score_ns": float(pd.to_numeric(group[f"{domain}_score_ns"], errors="coerce").fillna(0.0).sum())
            for domain in HARDWARE_BOTTLENECK_DOMAINS
        }
        bottleneck = max(
            HARDWARE_BOTTLENECK_DOMAINS,
            key=lambda domain: score_sums[f"{domain}_score_ns"],
        )
        if score_sums[f"{bottleneck}_score_ns"] <= 0.0:
            bottleneck = "unknown"
        op_time_ns = _numeric_column_sum(group, "op time")
        comm_time_ns = _numeric_column_sum(group, "comm time") + _numeric_column_sum(group, "pp comm time")
        pieces.append(
            {
                "phase": phase or "",
                "config_label": config_label,
                "component": "" if pd.isna(component) else str(component),
                "type": "" if pd.isna(op_type) else str(op_type),
                "row_count": int(len(group)),
                "op_time_s": float(op_time_ns) / 1e9,
                "comm_time_s": float(comm_time_ns) / 1e9,
                "bottleneck_domain": bottleneck,
                **score_sums,
            }
        )
    return pd.DataFrame(pieces).reindex(columns=output_columns)

