def _mtp_stage_gpu_nums(args: argparse.Namespace) -> list[str]:
    raw = str(args.mtp_stage_gpu_nums).strip().lower()
    if raw == "all":
        return parse_csv(args.gpu_nums)
    return parse_csv(args.mtp_stage_gpu_nums)

def build_command_plan(args: argparse.Namespace, python: str | None = None) -> list[CommandStep]:
    """Build the exact lower-level commands executed by the unified script."""
    python = python or sys.executable
    steps: list[CommandStep] = []
    if not args.skip_tables:
        steps.append(_table_command(args, python))
    if not args.skip_pareto:
        hardware = parse_csv(args.hardware)
        stage_gpu_nums = _mtp_stage_gpu_nums(args)
        multi_stage_nums = len(stage_gpu_nums) > 1
        for gpu_name in hardware:
            for stage_gpu_num in stage_gpu_nums:
                steps.append(_pareto_command(args, python, gpu_name, stage_gpu_num, multi_stage_nums))
    return steps

def main(argv: Sequence[str] | None = None) -> None:
    args = parse_args(argv)
    run_command_plan(build_command_plan(args), dry_run=args.dry_run, continue_on_error=args.continue_on_error)

def parse_csv(value: str) -> list[str]:
    """Parse a comma-separated CLI value while preserving order."""
    return [item.strip() for item in str(value).split(",") if item.strip()]

def run_command_plan(steps: Sequence[CommandStep], dry_run: bool = False, continue_on_error: bool = False) -> None:
    """Run or print each command in sequence."""
    failures: list[tuple[CommandStep, int]] = []
    for index, step in enumerate(steps, start=1):
        print(f"[{index}/{len(steps)}] {step.name}")
        print(shlex.join(step.argv))
        if dry_run:
            continue
        try:
            subprocess.run(step.argv, check=True)
        except subprocess.CalledProcessError as exc:
            if not continue_on_error:
                raise
            failures.append((step, int(exc.returncode)))
            print(f"[failed] {step.name} exited with {exc.returncode}; continuing")
    if failures:
        print("Continuing after failed steps:")
        for step, returncode in failures:
            print(f"  - {step.name}: exit {returncode}")

def _graph_info(path: Path) -> dict[str, Any] | None:
    match = re.match(r"(?P<model>.+)_i(?P<input>\d+)_o(?P<output>\d+)_(?P<precision>[^.]+)_graph\.json$", path.name)
    if not match:
        return None
    try:
        graph = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    model = graph.get("model") if isinstance(graph.get("model"), dict) else {}
    hf_arch = graph.get("hf_architecture") if isinstance(graph.get("hf_architecture"), dict) else {}
    model_name = str(model.get("model_name") or match.group("model").replace("_", "/", 1))
    cost_graphs = graph.get("cost_graphs") if isinstance(graph.get("cost_graphs"), dict) else {}
    return {
        "modelKey": _safe_model_name(model_name),
        "modelName": model_name,
        "modelType": str(hf_arch.get("model_type") or ""),
        "inputLen": int(model.get("input_seq_length") or match.group("input")),
        "outputLen": int(model.get("output_seq_length") or match.group("output")),
        "precision": str(model.get("precision") or match.group("precision")),
        "batch": int(model.get("batch") or model.get("max_batch_size") or 0),
        "graphPath": path,
        "nodeCounts": {
            "prefill": len(cost_graphs.get("prefill", {}).get("nodes", [])) if isinstance(cost_graphs.get("prefill"), dict) else 0,
            "decode": len(cost_graphs.get("decode", {}).get("nodes", [])) if isinstance(cost_graphs.get("decode"), dict) else 0,
        },
    }

def _is_web_table(path: Path) -> bool:
    if not path.exists():
        return False
    try:
        df = pd.read_excel(path, nrows=1)
    except Exception:
        return False
    return {"Config_Name", "model", "GPU", "Gpu num"}.issubset(set(df.columns))

def _model_aliases(model_key: str, model_name: str, model_type: str) -> set[str]:
    values = {model_key, model_name, _model_label(model_name), model_type}
    aliases = {_alias_norm(value) for value in values if value}
    aliases.update({_alias_compact(value) for value in values if value})

    joined = " ".join(str(value).lower() for value in values if value)
    deepseek = re.search(r"deepseek[^a-z0-9]*v(?P<version>\d+(?:[^a-z0-9]?\d+)?)", joined)
    if deepseek:
        version = re.sub(r"[^0-9]+", "", deepseek.group("version"))
        if version:
            aliases.update({f"dsv{version}", f"deepseekv{version}", f"deepseek_v{version}"})

    kimi = re.search(r"kimi[^a-z0-9]*k(?P<version>\d+(?:[^a-z0-9]?\d+)?)", joined)
    if kimi:
        version = re.sub(r"[^0-9]+", "", kimi.group("version"))
        if version:
            aliases.update({f"k{version}", f"kimi_k{version}", f"kimik{version}"})

    return {alias for alias in aliases if alias}

def _read_model_sheet(path: Path) -> dict[str, Any]:
    try:
        df = pd.read_excel(path, sheet_name="Model")
    except Exception:
        return {}
    if not {"field", "value"}.issubset(set(df.columns)):
        return {}
    return {str(row["field"]): row["value"] for _, row in df.iterrows()}

def _relative_to_web(path: Path | None, web_root: Path) -> str | None:
    if path is None:
        return None
    try:
        return path.resolve().relative_to(web_root.resolve()).as_posix()
    except ValueError:
        return path.as_posix()

def _sequence_label(input_len: int, output_len: int, precision: str) -> str:
    def short(value: int) -> str:
        return f"{value // 1024}K" if value % 1024 == 0 else str(value)

    return f"I{short(input_len)} / O{short(output_len)} / {precision}"

def _stem_matches_alias(stem: str, aliases: set[str]) -> bool:
    stem_norm = _alias_norm(stem)
    stem_compact = _alias_compact(stem)
    for alias in aliases:
        alias_norm = _alias_norm(alias)
        if alias_norm and re.search(rf"(^|_){re.escape(alias_norm)}($|_)", stem_norm):
            return True

        alias_compact = _alias_compact(alias)
        if not alias_compact:
            continue
        start = stem_compact.find(alias_compact)
        while start >= 0:
            end = start + len(alias_compact)
            next_char = stem_compact[end : end + 1]
            if not (alias_compact[-1].isdigit() and next_char.isdigit()):
                return True
            start = stem_compact.find(alias_compact, start + 1)
    return False

def _strategy_payload_info(path: Path, web_root: Path) -> dict[str, Any] | None:
    if not path.exists() or path.suffix != ".json":
        return None
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    points = payload.get("points")
    if not isinstance(points, list) or not points:
        return None
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    kind = "mtp_stage" if "mtp" in path.stem.lower() else "pareto"
    gpu_nums = sorted(
        {
            int(point["gpu_num"])
            for point in points
            if isinstance(point, dict) and point.get("gpu_num") is not None
        }
    )
    hardware = sorted(
        {
            str(point.get("hardware") or point.get("GPU"))
            for point in points
            if isinstance(point, dict) and (point.get("hardware") or point.get("GPU"))
        }
    )
    stages = sorted(
        {
            int(point["mtp_stage"])
            for point in points
            if isinstance(point, dict) and point.get("mtp_stage") is not None
        }
    )
    strategies = sorted(
        {
            _strategy_type(point, kind=kind)
            for point in points
            if isinstance(point, dict)
        }
    )
    return {
        "id": path.stem,
        "label": str(summary.get("title") or path.stem.replace("_", " ")),
        "path": _relative_to_web(path, web_root),
        "kind": kind,
        "hardware": hardware,
        "gpuNums": gpu_nums,
        "strategies": strategies,
        "stages": stages,
    }

