def _strategy_payloads(
    web_data_root: Path,
    model_key: str,
    model_name: str,
    model_type: str,
    input_len: int,
    output_len: int,
    web_root: Path,
) -> list[dict[str, Any]]:
    seq_dir = web_data_root / model_key / f"i{input_len}_o{output_len}"
    aliases = _model_aliases(model_key, model_name, model_type)
    candidate_paths: list[Path] = []
    if seq_dir.exists():
        candidate_paths.extend(sorted(seq_dir.glob("*.json")))

    for root in (web_data_root, web_data_root.parent):
        if not root.exists():
            continue
        for path in sorted(root.glob("*.json")):
            if _stem_matches_alias(path.stem, aliases):
                candidate_paths.append(path)

    payloads = []
    seen: set[Path] = set()
    for path in candidate_paths:
        resolved = path.resolve()
        if resolved in seen:
            continue
        seen.add(resolved)
        if "pareto" not in path.stem.lower() and "mtp" not in path.stem.lower():
            continue
        info = _strategy_payload_info(path, web_root)
        if info:
            payloads.append(info)
    return sorted(payloads, key=lambda item: (item["kind"] != "pareto", item["label"].lower(), item["id"]))

def _strategy_type(point: dict[str, Any], *, kind: str) -> str:
    raw = point.get("strategy_type")
    if raw:
        return str(raw)
    if point.get("pd_enabled") and point.get("af_enabled"):
        return "pd_af"
    if point.get("pd_enabled"):
        return "pd"
    if point.get("af_enabled"):
        return "af"
    if kind == "mtp_stage" or point.get("mtp_stage") is not None:
        return "mtp"
    return "monolithic"

def _table_paths(web_data_root: Path, model_key: str, input_len: int, output_len: int, web_root: Path) -> dict[str, str]:
    seq_dir = web_data_root / model_key / f"i{input_len}_o{output_len}"
    tables: dict[str, str] = {}
    for phase in ("prefill", "decode"):
        path = seq_dir / f"final_{phase}_all.xlsx"
        if _is_web_table(path):
            tables[phase] = _relative_to_web(path, web_root) or path.as_posix()
    return tables

def error(self, *args, **kwargs):
        """Ignore expected per-strategy rejection logs during table generation."""
        pass

def warning(self, *args, **kwargs):
        """Ignore expected per-strategy warning logs during table generation."""
        pass

def build_tasks(args) -> list[tuple]:
    """Build all requested web table generation tasks."""
    hardware = [resolve_gpu_name(name) for name in parse_csv_list(args.hardware)]
    gpu_nums = parse_int_list(args.gpu_nums)
    batches = parse_int_list(args.batches)
    tp_values = parse_int_list(args.tp_values)
    cp_values = parse_int_list(args.cp_values)
    pp_values = parse_int_list(args.pp_values)
    phases = parse_csv_list(args.phases)
    if args.map_mode == "cartesian":
        map_builder = generate_cartesian_sys_maps
    else:
        map_builder = generate_same_tp_sys_maps

    tasks = []
    for phase in phases:
        if phase not in ("prefill", "decode"):
            raise ValueError(f"unsupported phase: {phase}")
        for gpu_name in hardware:
            for gpu_num in gpu_nums:
                for gpu_config in map_builder(gpu_num, tp_values, cp_values, pp_values):
                    for batch_size in batches:
                        tasks.append((phase, gpu_name, gpu_num, batch_size, gpu_config, args.model_label))
    return tasks

def config_name(gpu_name: str, gpu_num: int, phase: str, batch_size: int, model_args, gpu_config: dict) -> str:
    """Build the same compact identifier shape used by cost_model result files."""
    prefix = f"{gpu_name}_{gpu_num}_{phase}_batch{batch_size}_I{model_args.input_seq_length}"
    if phase == "decode":
        prefix += f"_O{model_args.output_seq_length}"
    return (
        f"{prefix}_pp{gpu_config['pp']}"
        f"_attn_dp{gpu_config['attn_dp']}_tp{gpu_config['attn_tp']}_cp{gpu_config.get('attn_cp', 1)}"
        f"_ffn_dp{gpu_config['ffn_dp']}_tp{gpu_config['ffn_tp']}_ep{gpu_config['ffn_ep']}"
    )

def generate_cartesian_sys_maps(
    gpu_num: int,
    tp_values: list[int],
    cp_values: list[int] | None = None,
    pp_values: list[int] | None = None,
) -> list[dict]:
    """Generate the fuller attention-TP x FFN-TP strategy set."""
    maps = []
    legal_pp = [pp for pp in (pp_values if pp_values is not None else [1]) if pp > 0 and gpu_num % pp == 0]
    legal_tp = [tp for tp in tp_values if tp > 0 and gpu_num % tp == 0]
    legal_cp = [cp for cp in (cp_values if cp_values is not None else [1, 2, 4, 8]) if cp > 0 and gpu_num % cp == 0]
    for pp in legal_pp:
        for attn_tp in legal_tp:
            for attn_cp in legal_cp:
                if gpu_num % (pp * attn_tp * attn_cp) != 0:
                    continue
                for ffn_tp in legal_tp:
                    if gpu_num % (pp * ffn_tp) != 0:
                        continue
                    maps.append(
                        {
                            "pp": pp,
                            "attn_dp": gpu_num // (pp * attn_tp * attn_cp),
                            "attn_tp": attn_tp,
                            "attn_cp": attn_cp,
                            "attn_ep": 1,
                            "ffn_dp": 1,
                            "ffn_tp": ffn_tp,
                            "ffn_ep": gpu_num // (pp * ffn_tp),
                        }
                    )
    return maps

def generate_same_tp_sys_maps(
    gpu_num: int,
    tp_values: list[int],
    cp_values: list[int] | None = None,
    pp_values: list[int] | None = None,
) -> list[dict]:
    """Generate a compact legal strategy set for web tables.

    Attention and FFN use the same TP in this web summary set. This keeps the
    table generation bounded while covering the TP values exposed in the UI.
    """
    maps = []
    cp_candidates = cp_values if cp_values is not None else [1, 2, 4, 8]
    pp_candidates = pp_values if pp_values is not None else [1]
    for pp in pp_candidates:
        if pp <= 0 or gpu_num % pp != 0:
            continue
        for tp in tp_values:
            if tp <= 0 or gpu_num % (pp * tp) != 0:
                continue
            for attn_cp in cp_candidates:
                if attn_cp <= 0 or gpu_num % (pp * tp * attn_cp) != 0:
                    continue
                maps.append(
                    {
                        "pp": pp,
                        "attn_dp": gpu_num // (pp * tp * attn_cp),
                        "attn_tp": tp,
                        "attn_cp": attn_cp,
                        "attn_ep": 1,
                        "ffn_dp": 1,
                        "ffn_tp": tp,
                        "ffn_ep": gpu_num // (pp * tp),
                    }
                )
    return maps

def parse_csv_list(value: str) -> list[str]:
    """Parse a comma-separated CLI list while preserving original item text."""
    return [item.strip() for item in str(value).split(",") if item.strip()]

def _config_label(row) -> str:
    fields = []
    for key, prefix in (
        ("batch", "b"),
        ("attn_tp", "aTP"),
        ("attn_cp", "aCP"),
        ("ffn_tp", "fTP"),
        ("ffn_ep", "fEP"),
    ):
        if key not in row or pd.isna(row[key]):
            continue
        value = float(row[key])
        text = str(int(value)) if value.is_integer() else f"{value:.3g}"
        fields.append(f"{prefix}{text}")
    return " ".join(fields)

def _copy_to_web(paths: list[Path], web_data_dir: Path) -> dict[str, Path]:
    web_data_dir.mkdir(parents=True, exist_ok=True)
    copied = {}
    for path in paths:
        target = web_data_dir / path.name
        shutil.copy2(path, target)
        copied[path.name] = target
    return copied

def _metric_config(name: str) -> dict[str, str]:
    key = str(name).strip().lower().replace("-", "_")
    if key in {"tps", "tps_per_user", "decode", "decode_speed"}:
        key = "decode_speed"
    elif key in {"throughput", "throughput_gpu", "throughput_per_gpu", "tps_per_gpu"}:
        key = "throughput_per_gpu"
    if key not in EP_METRICS:
        raise ValueError(f"unknown EP metric: {name}")
    return EP_METRICS[key]

def _normalize_cp_value(value) -> str | int:
    text = str(value).strip().lower()
    if text in {"all", "best", "cpall", "cp-all", "0"}:
        return "all"
    parsed = int(text)
    if parsed <= 0:
        raise ValueError(f"CP values must be positive, got {parsed}")
    return parsed

def _parse_cp_values(text: str) -> list[str | int]:
    cleaned = str(text).strip().lower()
    if cleaned in {"", "default", "none"}:
        return DEFAULT_CP_VALUES.copy()
    values: list[str | int] = []
    seen = set()
    for part in cleaned.split(","):
        part = part.strip()
        if not part:
            continue
        value = _normalize_cp_value(part)
        key = str(value)
        if key in seen:
            continue
        seen.add(key)
        values.append(value)
    return values or DEFAULT_CP_VALUES.copy()

def _parse_ep_values(text: str) -> list[int] | None:
    cleaned = str(text).strip().lower()
    if cleaned in {"", "all", "none"}:
        return None
    values: list[int] = []
    for part in cleaned.split(","):
        part = part.strip()
        if not part:
            continue
        value = int(part)
        if value <= 0:
            raise ValueError(f"EP values must be positive, got {value}")
        values.append(value)
    return values or None

def _rows_for_cp(df: pd.DataFrame, cp_value: str | int) -> pd.DataFrame:
    normalized = _normalize_cp_value(cp_value)
    if normalized == "all":
        return df.copy()
    return df[_numeric(df, "attn_cp").eq(int(normalized))].copy()

