def _gpu_info_value(gpu_name: str, row: str, fallback: float | None = None) -> float:
    """Read a numeric gpu_info value with an optional fallback."""
    if fallback is not None:
        return float(fallback)
    table = load_gpu_info_table()
    try:
        value = table.loc[row, gpu_name]
        if pd.isna(value):
            raise ValueError
        return float(value)
    except (KeyError, TypeError, ValueError):
        if fallback is not None:
            return float(fallback)
        raise ValueError(f"missing numeric gpu_info value for {gpu_name}:{row}")

def _gpu_label(gpu_name: str) -> str:
    """Return a compact label for scenario names."""
    return GPU_LABELS.get(gpu_name, gpu_name)

def _token_labels(values: list[int]) -> list[str]:
    """Format token lengths as compact axis labels."""
    return [f"{value // 1024}k" if value % 1024 == 0 else str(value) for value in values]

def parse_int_list(value: str) -> list[int]:
    """Parse user input or CLI text into structured values."""
    return [int(item.strip()) for item in value.split(",") if item.strip()]

def parse_name_list(value: str) -> list[str]:
    """Parse comma-separated names while preserving user order."""
    return [item.strip() for item in str(value).split(",") if item.strip()]

def resolve_gpu_name(name: str) -> str:
    """Resolve user-facing GPU aliases into gpu_info.xlsx column names."""
    raw = str(name).strip()
    if not raw:
        raise ValueError("GPU name must be non-empty")
    alias = raw.lower()
    if alias in GPU_ALIASES:
        return GPU_ALIASES[alias]
    table = load_gpu_info_table()
    if raw in table.columns:
        return raw
    raise ValueError(f"unsupported GPU name '{name}'. Supported aliases: {', '.join(sorted(GPU_ALIASES))}")

def _division_key(work_map: dict) -> tuple[int, int, int]:
    return (
        int(work_map.get("ich_div", 1)),
        int(work_map.get("och_div", 1)),
        int(work_map.get("batch_div", 1)) * int(work_map.get("h_div", 1)),
    )

def _float_value(row: dict, key: str) -> float:
    try:
        return float(row.get(key, 0.0))
    except (TypeError, ValueError):
        return 0.0

def _literal_work_map(value) -> dict:
    if isinstance(value, dict):
        return value
    if value is None or pd.isna(value):
        return {}
    return ast.literal_eval(str(value))

def _tiled_batch_map(batches: list[int], min_kernel_n: int, tile_n: int) -> dict[int, int]:
    return {
