def ceil_to_tile(value: int, tile: int) -> int:
    safe_tile = max(int(tile), 1)
    return ((max(int(value), 0) + safe_tile - 1) // safe_tile) * safe_tile

def output_suffix(batches: list[int], gpu_aliases: list[str]) -> str:
    if not batches:
        raise ValueError("batches must not be empty")
    return f"gpu_batch{min(batches)}_{max(batches)}_{'_'.join(gpu_aliases)}"

def parse_models(values: list[str] | None) -> list[ExpertModelSpec]:
    if not values:
        return [MODEL_SPECS["deepseek-v3"], MODEL_SPECS["deepseek-v4-pro"]]
    specs = []
    for value in values:
        key = MODEL_ALIASES.get(value.lower(), value.lower())
        if key not in MODEL_SPECS:
            raise ValueError(f"Unknown model alias: {value}")
        specs.append(MODEL_SPECS[key])
    return specs

def work_map_active_sm_count(work_map: dict) -> int:
    return (
        int(work_map.get("ich_div", 1))
        * int(work_map.get("och_div", 1))
        * int(work_map.get("batch_div", 1))
        * int(work_map.get("h_div", 1))
    )

def work_map_valid_for_gemm(work_map: dict, m: int, n: int, k: int) -> bool:
    sm_n_div = int(work_map.get("batch_div", 1)) * int(work_map.get("h_div", 1))
    sm_m_div = int(work_map.get("och_div", 1))
    sm_k_div = int(work_map.get("ich_div", 1))
    return not ((int(m) > 0 and int(m) < sm_m_div) or int(n) < sm_n_div or int(k) < sm_k_div)

