def critical(self, *args, **kwargs):
        """Drop noisy cost-model logging during throughput sweeps."""
        pass

def debug(self, *args, **kwargs):
        """Drop noisy cost-model logging during throughput sweeps."""
        pass

def exception(self, *args, **kwargs):
        """Drop noisy cost-model logging during throughput sweeps."""
        pass

def info(self, *args, **kwargs):
        """Drop noisy cost-model logging during throughput sweeps."""
        pass

def _af_config_for_decode_row(config: DecodeAttnFfnSplitConfig, decode_row: pd.Series) -> DecodeAttnFfnSplitConfig:
    """Carry row-specific MTP emission rate into the LPX FFN stage model."""
    expected_tokens = float(decode_row.get("mtp_expected_tokens", 1.0) or 1.0)
    return replace(config, lpx_ffn_mtp_expected_tokens=max(expected_tokens, 1.0))

def _batch_column(df: pd.DataFrame) -> str | None:
    if "batch_attn_gpu" in df.columns:
        return "batch_attn_gpu"
    if "Batch" in df.columns:
        return "Batch"
    if "batch" in df.columns:
        return "batch"
    return None

def _best_by_batch_config_summary(row) -> str:
    """Return a compact full-configuration label for one best-by-batch point."""
    parts = [_compact_config_summary(row)]
    if _row_has_value(row, "dominant_component"):
        parts.append(f"bt={_format_config_value(row['dominant_component'])}")
    return " ".join(parts) if parts else "best point"

def _best_pd_prefill_rows(matching_prefill: pd.DataFrame) -> pd.DataFrame:
    """Keep the highest-throughput prefill candidate for each batch."""
    if matching_prefill.empty:
        return matching_prefill.copy()
    rows = matching_prefill.copy()
    rows["_pd_prefill_rank"] = _pd_prefill_rank(rows)
    batch_col = _batch_column(rows)
    rows = rows.sort_values("_pd_prefill_rank", ascending=False)
    if batch_col is None:
        return rows.head(1).drop(columns=["_pd_prefill_rank"])
    return rows.groupby(batch_col, as_index=False).head(1).drop(columns=["_pd_prefill_rank"])

def _bool_series(df: pd.DataFrame, name: str, default: bool = False) -> pd.Series:
    """Return a boolean column with a scalar default when the column is absent."""
    if name not in df.columns:
        return pd.Series(default, index=df.index, dtype=bool)
    return df[name].fillna(default).astype(bool)

def _ceil_div_int(numerator: int | float, denominator: int | float) -> int:
    denominator = max(int(denominator), 1)
    return max(int(math.ceil(float(numerator) / float(denominator))), 1)

def _coerce_numeric_value(value):
    if value is None:
        return None
    if isinstance(value, (int, np.integer)):
        return int(value)
    if isinstance(value, (float, np.floating)):
        number = float(value)
        return number if math.isfinite(number) else None
    try:
        if pd.isna(value):
            return None
    except (TypeError, ValueError):
        pass
    text = str(value).strip()
    if not text:
        return None
    try:
        number = float(text)
    except ValueError:
        return None
    return number if math.isfinite(number) else None

def _compact_config_summary(row) -> str:
    parts = []
    batch_attn = f"attnGPU_b{_row_config_text(row, 'batch_attn_gpu')}" if _row_has_value(row, "batch_attn_gpu") else ""
    batch_ffn = f"ffnGPU_b{_row_config_text(row, 'batch_ffn_gpu')}" if _row_has_value(row, "batch_ffn_gpu") else ""
    batch_total = f"total_b{_row_config_text(row, 'total_machine_batch')}" if _row_has_value(row, "total_machine_batch") else ""
    gpu = f"g{_format_config_value(row['gpu_num'])}" if _row_has_value(row, "gpu_num") else ""
    pp = f"pp{_format_config_value(row['pp'])}" if _row_has_value(row, "pp") else ""
    attn = ""
    if any(_row_has_value(row, key) for key in ("attn_dp", "attn_tp", "attn_ep", "attn_cp")):
        attn = (
            "a(d/t/e/c)="
            f"{_row_config_text(row, 'attn_dp')}/"
            f"{_row_config_text(row, 'attn_tp')}/"
            f"{_row_config_text(row, 'attn_ep')}/"
            f"{_row_config_text(row, 'attn_cp')}"
        )
    ffn = ""
    if any(_row_has_value(row, key) for key in ("ffn_dp", "ffn_tp", "ffn_ep")):
        ffn = (
            "f(d/t/e)="
            f"{_row_config_text(row, 'ffn_dp')}/"
            f"{_row_config_text(row, 'ffn_tp')}/"
            f"{_row_config_text(row, 'ffn_ep')}"
        )
    stage = f"mtp_s{_format_config_value(row['mtp_stage'])}" if _row_has_value(row, "mtp_stage") else ""
    split = []
    if _row_has_value(row, "pd_enabled") and _format_config_value(row["pd_enabled"]) == "on":
        split.append("PD")
    if _row_has_value(row, "af_enabled") and _format_config_value(row["af_enabled"]) == "on":
        split.append("AF")
    prefill = ""
    if _row_has_value(row, "prefill_gpu_num"):
        prefill_gpu = _row_numeric_value(row, "prefill_gpu_num")
        if prefill_gpu is not None and int(prefill_gpu) > 0:
            prefill = (
                f"prefill{_format_config_value(prefill_gpu)}:"
                f"attnGPU_b{_row_config_text(row, 'prefill_batch_attn_gpu', fallback='batch_attn_gpu', default='0')}"
            )
        else:
            prefill = "prefill=off"
    decode = ""
    if _row_has_value(row, "decode_gpu_num") or _row_has_value(row, "gpu_num"):
        decode = (
            f"decode{_row_config_text(row, 'decode_gpu_num', fallback='gpu_num', default='0')}"
            f":attnGPU_b{_row_config_text(row, 'decode_batch_attn_gpu', fallback='batch_attn_gpu', default='0')}"
        )
    for item in (batch_attn, batch_ffn, batch_total, gpu, pp, attn, ffn, stage, *split, prefill, decode):
        if item:
            parts.append(item)
    return " ".join(parts) if parts else "frontier start"

def _component_latency_s(df: pd.DataFrame, components: tuple[str, ...], output_tokens: pd.Series) -> pd.Series:
    total_tpot = pd.Series(0.0, index=df.index, dtype=float)
    for component in components:
        total_tpot = total_tpot + _numeric_column(df, component)
    return total_tpot * output_tokens

def _data_parser_with_batch(data_parser, batch_value: int):
    values = list(data_parser)
    values[9] = int(batch_value)
    return tuple(values)

def _decode_dense_attention_row(row, model_args: ModelArgs) -> bool:
    attention_type = str(_row_value(row, "attention_type", "") or "").strip().lower()
    if attention_type in {"mla", "hca", "csa", "dsa", "linear_attention", "mhc"}:
        return False
    if attention_type in {"mha", "gqa", "mqa"}:
        return True
    return not _model_uses_mla_cache(model_args)

def _decode_kv_cache_bpe(model_args: ModelArgs) -> float:
    """Return KV-cache bytes per element; default decode KV cache is MXFP8/FP8."""
    return _positive_float(getattr(model_args, "kv_cache_bpe", 1.0), 1.0)

def _decode_kv_cache_elements_from_layers(model_args: ModelArgs, decode_layers: pd.DataFrame | None) -> float:
    if decode_layers is None or decode_layers.empty:
        return 0.0

    elements = 0.0
    for _, row in decode_layers.iterrows():
        component = str(_row_value(row, "component", "") or "").strip().lower()
        role = str(_row_value(row, "attention_role", "") or "").strip().lower()
        if component == "attention_core" and role == "qk_softmax_sv":
            kv_seq = _positive_float(_row_value(row, "effective_kv_seq", 0), 0.0)
            layer_count = _positive_float(_row_value(row, "layer", 1), 1.0)
            kv_heads = _positive_float(_row_value(row, "kv_head", getattr(model_args, "head_kv", 1)), 1.0)
            if kv_seq <= 0 or layer_count <= 0:
                continue
            if _decode_dense_attention_row(row, model_args):
                head_dim = _decode_kv_head_dim(model_args, kv_heads)
                if head_dim > 0:
                    elements += kv_seq * 2.0 * kv_heads * head_dim * layer_count
            else:
                hidden = _positive_float(_row_value(row, "c_out", 0), 0.0)
                if hidden > 0:
                    elements += kv_seq * hidden * kv_heads * layer_count
        elif component in {"dsa_indexer", "csa_indexer"} and role == "index_score_topk":
            kv_seq = _positive_float(_row_value(row, "effective_kv_seq", 0), 0.0)
            index_dim = _positive_float(_row_value(row, "index_head_dim", 0), 0.0)
            if index_dim <= 0:
                index_dim = _positive_float(_row_value(row, "c_in", 0), 0.0)
            layer_count = _positive_float(_row_value(row, "layer", 1), 1.0)
            if kv_seq > 0 and index_dim > 0 and layer_count > 0:
                elements += kv_seq * index_dim * layer_count
    return elements

def _decode_kv_cache_fallback_elements(model_args: ModelArgs) -> float:
    kv_heads = _positive_float(getattr(model_args, "head_kv", 1), 1.0)
    layer_count = _positive_float(getattr(model_args, "layer", getattr(model_args, "n_layers", 1)), 1.0)
    kv_seq = _positive_float(
        getattr(model_args, "input_seq_length", 0) + getattr(model_args, "output_seq_length", 0),
        0.0,
    )
    if not _model_uses_mla_cache(model_args):
        return 2.0 * kv_heads * _decode_kv_head_dim(model_args, kv_heads) * layer_count * kv_seq
    return (
        (_positive_float(getattr(model_args, "compress_kv", 0), 0.0) + _positive_float(getattr(model_args, "rope_dim", 0), 0.0))
        * kv_heads
        * layer_count
        * kv_seq
    )

def _decode_kv_cache_has_dense_attention(model_args: ModelArgs, decode_layers: pd.DataFrame | None) -> bool:
    if decode_layers is None or decode_layers.empty:
        return not _model_uses_mla_cache(model_args)
    for _, row in decode_layers.iterrows():
        component = str(_row_value(row, "component", "") or "").strip().lower()
        role = str(_row_value(row, "attention_role", "") or "").strip().lower()
        if component == "attention_core" and role == "qk_softmax_sv" and _decode_dense_attention_row(row, model_args):
            return True
    return False

def _decode_kv_cache_tp_shard_factor(model_args: ModelArgs, gpu_config: dict, decode_layers: pd.DataFrame | None = None) -> float:
    if not _decode_kv_cache_has_dense_attention(model_args, decode_layers):
        return 1.0
    kv_heads = _positive_float(getattr(model_args, "head_kv", 1), 1.0)
    if decode_layers is not None and not decode_layers.empty:
        for _, row in decode_layers.iterrows():
            component = str(_row_value(row, "component", "") or "").strip().lower()
            role = str(_row_value(row, "attention_role", "") or "").strip().lower()
            if component == "attention_core" and role == "qk_softmax_sv" and _decode_dense_attention_row(row, model_args):
                kv_heads = _positive_float(_row_value(row, "kv_head", kv_heads), kv_heads)
                break
    if kv_heads <= 0:
        return 1.0
    attn_tp = _positive_int(gpu_config.get("attn_tp", 1), 1)
    return math.ceil(kv_heads / float(attn_tp)) / kv_heads

def _decode_kv_head_dim(model_args: ModelArgs, kv_heads: float) -> float:
    v_head_dim = _positive_float(getattr(model_args, "v_head_dim", 0), 0.0)
    if v_head_dim > 0:
        return v_head_dim
    if kv_heads > 0:
        per_head_compress = _positive_float(getattr(model_args, "compress_kv", 0), 0.0) / kv_heads
        if per_head_compress > 0:
            return per_head_compress
    head_q = _positive_float(getattr(model_args, "head_q", 0), 0.0)
    hidden = _positive_float(getattr(model_args, "hidden", getattr(model_args, "dim", 0)), 0.0)
    if head_q > 0 and hidden > 0:
        return hidden / head_q
    return _positive_float(getattr(model_args, "compress_kv", 0), 0.0)

def _ffn_cost_model_rows(base_decode: pd.DataFrame) -> pd.DataFrame:
    """Return only rows assigned to the FFN parallel domain."""
    if base_decode is None or base_decode.empty or "gpu_config_tuning" not in base_decode.columns:
        return pd.DataFrame()
    tuning = base_decode["gpu_config_tuning"].fillna("").astype(str).str.strip().str.lower()
    return base_decode[tuning.eq("ffn")].copy().reset_index(drop=True)

def _ffn_domain_all_reduce_time_s(llm_data: pd.DataFrame, fallback_s: float) -> float:
    """Sum FFN-stage all-reduce from rows that actually use the FFN parallel domain."""
    required = {"component", "gpu_config_tuning", "gpu_comm", "tp comm time", "layer"}
    if not required.issubset(llm_data.columns):
        return fallback_s

    component = llm_data["component"].fillna("").astype(str).str.strip().str.lower()
    tuning = llm_data["gpu_config_tuning"].fillna("").astype(str).str.strip().str.lower()
    comm = llm_data["gpu_comm"].fillna("").astype(str).str.strip().str.lower()
    mask = component.isin(_FFN_ALL_REDUCE_COMPONENTS) & tuning.eq("ffn") & comm.eq("allreduce")
    if not bool(mask.any()):
        return 0.0

    tp_comm_ns = pd.to_numeric(llm_data.loc[mask, "tp comm time"], errors="coerce").fillna(0.0)
    layers = pd.to_numeric(llm_data.loc[mask, "layer"], errors="coerce").fillna(1.0)
    return float((tp_comm_ns * layers).sum() / 1e9)

def _filter_rows_by_model_limits(
    df: pd.DataFrame,
    model_args: ModelArgs | None,
    allow_over_routed_ffn_ep: bool = False,
) -> pd.DataFrame:
    """Drop result rows whose FFN EP exceeds the model routed-expert count."""
    if allow_over_routed_ffn_ep:
        return df.copy() if isinstance(df, pd.DataFrame) else df
    if df is None or df.empty or model_args is None or "ffn_ep" not in df.columns:
        return df.copy() if isinstance(df, pd.DataFrame) else df
    routed_experts = _model_routed_expert_limit(model_args)
    if routed_experts <= 0:
        return df.copy()
    ffn_ep = pd.to_numeric(df["ffn_ep"], errors="coerce").fillna(1)
    return df[ffn_ep <= routed_experts].copy()

def _format_config_value(value) -> str:
    if isinstance(value, (bool, np.bool_)):
        return "on" if bool(value) else "off"
    if isinstance(value, (int, np.integer)):
        return str(int(value))
    if isinstance(value, (float, np.floating)):
        if not math.isfinite(float(value)):
            return str(value)
        return str(int(value)) if float(value).is_integer() else f"{float(value):.4g}"
    text = str(value)
    if text in ("True", "False"):
        return "on" if text == "True" else "off"
    return text

def _frame_has_batch_input(df: pd.DataFrame) -> bool:
    return any(
        column in df.columns
        for column in (
            "batch",
            "Batch",
            "batch_attn_gpu",
            "batch_ffn_gpu",
            "total_machine_batch",
            "decode_batch",
            "decode_batch_attn_gpu",
        )
    )

def _gpu_info_value(gpu_name: str, row: str, fallback: float | None = None) -> float:
    """Read a numeric GPU info value for strategy-level communication modeling."""
    table = load_gpu_info_table()
    try:
        value = table.loc[row, gpu_name]
        if isinstance(value, pd.Series):
            values = pd.to_numeric(value, errors="coerce").dropna()
            if values.empty:
                raise ValueError
            value = values.iloc[-1]
        if pd.isna(value):
            raise ValueError
        return float(value)
    except (KeyError, TypeError, ValueError):
        if fallback is not None:
            return float(fallback)
        raise ValueError(f"missing numeric gpu_info value for {gpu_name}:{row}")

def _json_records(df: pd.DataFrame) -> list[dict]:
    """Convert a DataFrame to JSON-safe row dictionaries."""
    return json.loads(df.to_json(orient="records"))

def _lpx3_sram_bytes(ffn_gpu: str) -> float:
    """Read LPX SRAM capacity from the SRAM-sized shared-memory row."""
    return _gpu_info_value(ffn_gpu, "shm_size", 0.0) * 1024.0

def _lpx_cost_model_ffn_components_from_row(row) -> dict[str, float]:
    """Read LPX cost-model FFN component columns from a strategy row."""
    components: dict[str, float] = {}
    for component, column in LPX_COST_MODEL_FFN_COMPONENT_COLUMNS.items():
        if column not in row:
            continue
        value = row[column]
        if value is None or pd.isna(value):
            continue
        components[component] = float(value)
    return components

def _lpx_device_count_for_gpu_nodes(gpu_name: str, total_gpu_num: int) -> int:
    """Use one LPX3 node per GPU node."""
    gpu_per_node = max(int(_gpu_info_value(gpu_name, "gpu_per_node", 1)), 1)
    return max(int(math.ceil(int(total_gpu_num) / gpu_per_node)), 1)

def _mode_summary(row) -> str:
    return (
        f"MTP={'on' if _row_mtp_enabled(row) else 'off'} "
        f"PD={'on' if _row_bool(row, 'pd_enabled', False) else 'off'} "
        f"AF={'on' if _row_bool(row, 'af_enabled', False) else 'off'}"
    )

def _model_routed_expert_limit(model_args: ModelArgs) -> int:
    """Return the routed-expert count used as the FFN EP upper bound."""
    for name in ("n_routed_experts", "expert", "experts"):
        value = getattr(model_args, name, None)
        if value is None:
            continue
        parsed = _positive_int(value, 0)
        if parsed > 0:
            return parsed
    return 0

def _model_uses_mla_cache(model_args: ModelArgs) -> bool:
    value = getattr(model_args, "MLA", True)
    if isinstance(value, str):
        return value.strip().lower() in {"1", "true", "yes", "y"}
    return bool(value)

def _mtp_enabled_series(df: pd.DataFrame) -> pd.Series:
    """Treat either explicit mtp_on or a positive MTP stage as MTP-enabled."""
    mtp_on = _bool_series(df, "mtp_on", False)
    if "mtp_stage" not in df.columns:
        return mtp_on
    stage = pd.to_numeric(df["mtp_stage"], errors="coerce").fillna(0)
    return mtp_on | (stage > 0)

def _normalized_mtp_stages(stages) -> list[int]:
    """Return sorted unique MTP stages as integers."""
    return sorted({int(stage) for stage in stages})

def _numeric_column(df: pd.DataFrame, column: str, default: float = 0.0) -> pd.Series:
    if column not in df.columns:
        return pd.Series(default, index=df.index, dtype=float)
    return pd.to_numeric(df[column], errors="coerce").fillna(default).astype(float)

def _pd_inter_node_aggregate_bandwidth_GBps(total_gpu_num: int, gpu_per_node: int, nic_bw_per_gpu_GBps: float) -> float:
    """Estimate PD KV-transfer stage bandwidth from participating GPU-node NIC capacity."""
    total = max(int(total_gpu_num), 1)
    per_node = max(int(gpu_per_node), 1)
    prefill_gpu_num = pd_prefill_gpu_count(total)
    decode_gpu_num = total - prefill_gpu_num
    if prefill_gpu_num <= 0 or decode_gpu_num <= 0:
        return float(nic_bw_per_gpu_GBps)

    prefill_nodes = math.ceil(prefill_gpu_num / per_node)
    decode_nodes = math.ceil(decode_gpu_num / per_node)
    active_node_pairs = max(min(prefill_nodes, decode_nodes), 1)
    return active_node_pairs * per_node * float(nic_bw_per_gpu_GBps)

def _pd_prefill_rank(rows: pd.DataFrame) -> pd.Series:
    if "throughput_total_tps" in rows.columns:
        return pd.to_numeric(rows["throughput_total_tps"], errors="coerce").fillna(0)
    if "TPS per gpu" in rows.columns:
        per_gpu = pd.to_numeric(rows["TPS per gpu"], errors="coerce").fillna(0)
        if "Gpu num" in rows.columns:
            return per_gpu * pd.to_numeric(rows["Gpu num"], errors="coerce").fillna(1)
        if "gpu_num" in rows.columns:
            return per_gpu * pd.to_numeric(rows["gpu_num"], errors="coerce").fillna(1)
        return per_gpu
    if "TPS per user" in rows.columns:
        return pd.to_numeric(rows["TPS per user"], errors="coerce").fillna(0)
    if "tps_per_user" in rows.columns:
        return pd.to_numeric(rows["tps_per_user"], errors="coerce").fillna(0)
    return pd.Series(1.0, index=rows.index)

def _pd_rows(
    prefill_rows: pd.DataFrame | None,
    decode_rows: pd.DataFrame | None,
    gpu_name: str,
    gpu_nums: list[int],
    model_args: ModelArgs | None,
    include_af: bool,
) -> pd.DataFrame:
    """Create PD or PD+AF split points using the fixed-budget prefill/decode split policy."""
    if prefill_rows is None or decode_rows is None or prefill_rows.empty or decode_rows.empty:
        return pd.DataFrame()
    pref = prefill_rows.copy()
    dec = decode_rows.copy()
    pref_gpu_col = "GPU" if "GPU" in pref.columns else "hardware"
    dec_gpu_col = "GPU" if "GPU" in dec.columns else "hardware"
    pref = pref[pref[pref_gpu_col] == gpu_name]
    dec = dec[dec[dec_gpu_col] == gpu_name]
    if "gpu_num" not in dec.columns and "Gpu num" in dec.columns:
        dec = dec.rename(columns={"Gpu num": "gpu_num", "Batch": "batch_attn_gpu"})
    dec = _with_explicit_batch_columns(dec)
    if "Gpu num" in pref.columns:
        pref_gpu_numbers = pd.to_numeric(pref["Gpu num"], errors="coerce")
    elif "gpu_num" in pref.columns:
        pref_gpu_numbers = pd.to_numeric(pref["gpu_num"], errors="coerce")
    else:
        return pd.DataFrame()
    if "gpu_num" not in dec.columns:
        return pd.DataFrame()
    dec_gpu_numbers = pd.to_numeric(dec["gpu_num"], errors="coerce")
    rows = []
    for gpu_num in gpu_nums:
        total_gpu_num = int(gpu_num)
        prefill_gpu_num = pd_prefill_gpu_count(total_gpu_num)
        decode_gpu_num = total_gpu_num - prefill_gpu_num
        if prefill_gpu_num <= 0 or decode_gpu_num <= 0:
            continue
        pd_config = _pd_transfer_config_for_strategy(gpu_name, model_args, total_gpu_num)
        af_config = (
            _af_split_config_for_strategy(
                gpu_name,
                model_args,
                lpx_device_count=_lpx_device_count_for_gpu_nodes(gpu_name, total_gpu_num),
            )
            if include_af
            else None
        )
        matching_prefill = _best_pd_prefill_rows(pref[pref_gpu_numbers == prefill_gpu_num])
        matching_decode = dec[dec_gpu_numbers == decode_gpu_num]
        prefill_batch_col = _batch_column(matching_prefill)
        for _, decode_row in matching_decode.iterrows():
            decode_batch = _row_batch_attn_gpu(decode_row, 0)
            if prefill_batch_col is None:
                candidate_prefill = matching_prefill
            else:
                prefill_batches = pd.to_numeric(matching_prefill[prefill_batch_col], errors="coerce")
                candidate_prefill = matching_prefill[prefill_batches == decode_batch]
            for _, prefill_row in candidate_prefill.iterrows():
                prefill = _phase_from_strategy_row(prefill_row, "prefill", gpu_name, prefill_gpu_num)
                decode = _phase_from_strategy_row(decode_row, "decode", gpu_name, decode_gpu_num)
                decode = _phase_with_lpx_cost_model_ffn_components(decode, decode_row)
                row_af_config = _af_config_for_decode_row(af_config, decode_row) if af_config is not None else None
                result = combine_disaggregated_pair(
                    prefill,
                    decode,
                    transfer_config=pd_config,
                    decode_split_config=row_af_config,
                )
                rows.append(
                    _row_from_disaggregated_result(result, decode_row, "pd_af" if include_af else "pd", total_gpu_num)
                )
    return pd.DataFrame(rows)

def _phase_from_strategy_row(row, phase: str, gpu_name: str, gpu_num: int | None = None) -> PhaseResult:
    """Convert a Pareto strategy row into the PhaseResult schema used by disaggregation helpers."""
    row_dict = dict(row)
    if "Config_Name" not in row_dict:
        row_dict["Config_Name"] = row_dict.get("name", f"{phase}-{gpu_num or row_dict.get('gpu_num', 1)}_I1024_O8192")
    row_dict["GPU"] = row_dict.get("GPU", row_dict.get("hardware", gpu_name))
    row_dict["Gpu num"] = int(gpu_num if gpu_num is not None else row_dict.get("gpu_num", row_dict.get("Gpu num", 1)))
    row_dict["Batch"] = int(
        row_dict.get(
            "batch_attn_gpu",
            row_dict.get("decode_batch_attn_gpu", row_dict.get("batch", row_dict.get("Batch", 1))),
        )
    )
    if "TPOT" not in row_dict:
        row_dict["TPOT"] = float(row_dict.get("tpot_ms", 0.0)) / 1000.0 if "tpot_ms" in row_dict else float(row_dict.get("tpot_ns", 0.0)) / 1e9
    row_dict["TPS per user"] = float(row_dict.get("tps_per_user", row_dict.get("TPS per user", 0.0)))
    row_dict["TPS per gpu"] = float(row_dict.get("tps_per_gpu", row_dict.get("TPS per gpu", 0.0)))
    row_dict["throughput_total_tps"] = float(
        row_dict.get("throughput_total_tps", row_dict["TPS per gpu"] * row_dict["Gpu num"])
    )
    return phase_result_from_row(pd.Series(row_dict), phase=phase)

