def _phase_with_lpx_cost_model_ffn_components(decode: PhaseResult, decode_row) -> PhaseResult:
    """Replace decode FFN components with LPX cost-model values when present."""
    lpx_components = _lpx_cost_model_ffn_components_from_row(decode_row)
    if len(lpx_components) != len(LPX_COST_MODEL_FFN_COMPONENT_COLUMNS):
        return decode
    components = dict(decode.components or {})
    components.update(lpx_components)
    return replace(decode, components=components)

def _plot_annotation_text(row, max_chars: int = 120) -> str:
    """Build a readable annotation label without letting very long diffs dominate the chart."""
    summary = str(row.get("config_summary", _best_by_batch_config_summary(row)))
    change = str(row.get("changed_parameters", ""))
    if change and change not in {summary, "first best point"}:
        text = f"{summary}\nchange: {change}"
    else:
        text = summary
    return text if len(text) <= max_chars else f"{text[: max_chars - 3]}..."

def _positive_float(value, default: float = 1.0) -> float:
    try:
        parsed = float(value)
    except (TypeError, ValueError):
        return default
    if math.isnan(parsed) or parsed < 0:
        return default
    return parsed

def _positive_int(value, default: int = 1) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    return parsed if parsed > 0 else default

def _prefill_config_summary(row) -> str:
    prefill_gpu = _row_numeric_value(row, "prefill_gpu_num")
    if prefill_gpu is None or int(prefill_gpu) <= 0:
        return "prefill off"
    prefill_batch = _row_config_text(row, "prefill_batch_attn_gpu", fallback="batch_attn_gpu", default="0")
    return f"prefill g={_format_config_value(prefill_gpu)} attnGPU_b={prefill_batch}"

def _raw_mtp_off(df: pd.DataFrame) -> pd.DataFrame:
    """Return baseline rows, filtering out synthetic MTP sweep rows when present."""
    if "mtp_on" not in df.columns:
        return df.copy()
    return df[df["mtp_on"] == False].copy()

def _row_batch_attn_gpu(row, default: int = 1) -> int:
    for key in ("batch_attn_gpu", "decode_batch_attn_gpu", "Batch", "batch", "decode_batch"):
        if _row_has_value(row, key):
            value = _row_numeric_value(row, key)
            if value is not None:
                return max(int(value), 1)
    return default

def _row_bool(row, key: str, default: bool = False) -> bool:
    if not _row_has_value(row, key):
        return default
    value = row[key]
    if isinstance(value, (bool, np.bool_)):
        return bool(value)
    if isinstance(value, (int, np.integer, float, np.floating)):
        if not math.isfinite(float(value)):
            return default
        return float(value) != 0.0
    text = str(value).strip().lower()
    if text in {"true", "1", "yes", "on"}:
        return True
    if text in {"false", "0", "no", "off"}:
        return False
    return default

def _row_config_text(row, key: str, fallback=None, default: str = "?") -> str:
    value = _row_numeric_value(row, key, fallback=fallback)
    if value is None:
        return default
    return _format_config_value(value)

def _row_has_value(row, key: str) -> bool:
    if key not in row:
        return False
    value = row[key]
    if value is None or pd.isna(value):
        return False
    return str(value) != ""

def _row_mtp_enabled(row) -> bool:
    if _row_bool(row, "mtp_on", False):
        return True
    stage = _row_numeric_value(row, "mtp_stage")
    return bool(stage is not None and float(stage) > 0)

def _row_numeric_value(row, key: str, fallback=None):
    if _row_has_value(row, key):
        value = _coerce_numeric_value(row[key])
        if value is not None:
            return value
    if fallback is not None and _row_has_value(row, fallback):
        value = _coerce_numeric_value(row[fallback])
        if value is not None:
            return value
    return None

def _row_value(row, name: str, default=0):
    if hasattr(row, "get"):
        value = row.get(name, default)
    else:
        value = getattr(row, name, default)
    if pd.isna(value):
        return default
    return value

def _simulated_mtp_rows(
    rows: pd.DataFrame,
    gpu_name: str,
    gpu_nums: list[int],
    stages,
    strategy_type: str = "mtp",
    preserve_split: bool = False,
) -> pd.DataFrame:
    """Return C++-simulated MTP rows from the raw decode sweep."""
    if rows is None or rows.empty:
        return pd.DataFrame()
    stage_values = [stage for stage in _normalized_mtp_stages(stages) if stage > 0]
    if not stage_values:
        return rows.iloc[0:0].copy()

    mtp_rows = _with_explicit_batch_columns(rows)
    if "hardware" in mtp_rows.columns:
        mtp_rows = mtp_rows[mtp_rows["hardware"] == gpu_name]
    if "gpu_num" not in mtp_rows.columns or "mtp_stage" not in mtp_rows.columns:
        return mtp_rows.iloc[0:0].copy()

    mtp_rows["gpu_num"] = pd.to_numeric(mtp_rows["gpu_num"], errors="coerce")
    mtp_rows["mtp_stage"] = pd.to_numeric(mtp_rows["mtp_stage"], errors="coerce")
    mtp_rows = mtp_rows[
        _mtp_enabled_series(mtp_rows)
        & mtp_rows["gpu_num"].isin([int(gpu_num) for gpu_num in gpu_nums])
        & mtp_rows["mtp_stage"].isin(stage_values)
    ].copy()
    if mtp_rows.empty:
        return mtp_rows

    mtp_rows["gpu_num"] = mtp_rows["gpu_num"].astype(int)
    mtp_rows["mtp_stage"] = mtp_rows["mtp_stage"].astype(int)
    mtp_rows["strategy_type"] = strategy_type
    mtp_rows["deployment_mode"] = strategy_type
    mtp_rows["mtp_model"] = mtp_rows.get("mtp_model", "simulated").fillna("simulated")
    if preserve_split:
        if "pd_enabled" not in mtp_rows:
            mtp_rows["pd_enabled"] = False
        if "af_enabled" not in mtp_rows:
            mtp_rows["af_enabled"] = False
        if "decode_ffn_gpu" not in mtp_rows:
            mtp_rows["decode_ffn_gpu"] = ""
        if "prefill_gpu_num" not in mtp_rows:
            mtp_rows["prefill_gpu_num"] = 0
        if "decode_gpu_num" not in mtp_rows:
            mtp_rows["decode_gpu_num"] = mtp_rows["gpu_num"].astype(int)
    else:
        mtp_rows["pd_enabled"] = False
        mtp_rows["af_enabled"] = False
        mtp_rows["decode_ffn_gpu"] = ""
        mtp_rows["prefill_gpu_num"] = 0
        mtp_rows["decode_gpu_num"] = mtp_rows["gpu_num"].astype(int)
    return mtp_rows

def _simulated_mtp_stage_rows(df: pd.DataFrame, gpu_name: str, gpu_num: int, stages) -> pd.DataFrame:
    """Build the MTP stage chart data from raw C++ simulation rows."""
    if df.empty:
        return df.copy()
    stage_values = _normalized_mtp_stages(stages)
    pieces = []
    if 0 in stage_values:
        base = _raw_mtp_off(df)
        if "hardware" in base.columns:
            base = base[base["hardware"] == gpu_name]
        base = base[pd.to_numeric(base["gpu_num"], errors="coerce") == int(gpu_num)].copy()
        if not base.empty:
            base["mtp_stage"] = 0
            base["mtp_model"] = "simulated_baseline"
            base["mtp_on"] = False
            base["mtp_effective_speedup"] = 1.0
            base["mtp_latency_multiplier"] = 1.0
            base["mtp_latency_overhead"] = 0.0
            pieces.append(base)
    simulated = _simulated_mtp_rows(df, gpu_name, [int(gpu_num)], stage_values, strategy_type="mtp")
    if not simulated.empty:
        pieces.append(simulated)
    if not pieces:
        return df.iloc[0:0].copy()
    return pd.concat(pieces, ignore_index=True)

def _stage_cost_pareto_rows(rows: pd.DataFrame) -> pd.DataFrame:
    """Return Pareto-frontier rows used by the stage cost stack plot."""
    if rows.empty:
        return rows.copy()

    ranked = rows.copy()
    ranked["throughput_total_tps"] = pd.to_numeric(ranked["throughput_total_tps"], errors="coerce").fillna(0)
    if "tps_per_user" not in ranked.columns:
        return ranked.sort_values("throughput_total_tps", ascending=False).head(1).copy()

    ranked["tps_per_user"] = pd.to_numeric(ranked["tps_per_user"], errors="coerce")
    ranked = ranked.dropna(subset=["tps_per_user", "throughput_total_tps"])
    if ranked.empty:
        return rows.sort_values("throughput_total_tps", ascending=False).head(1).copy()

    if "gpu_num" not in ranked.columns:
        return compute_pareto_frontier(ranked, y_col="throughput_total_tps")

    def gpu_sort_key(value) -> int:
        try:
            return int(value)
        except (TypeError, ValueError):
            return 0

    pieces = []
    for gpu_num, group in sorted(ranked.groupby("gpu_num"), key=lambda item: gpu_sort_key(item[0])):
        frontier = compute_pareto_frontier(group, y_col="throughput_total_tps").copy()
        if frontier.empty:
            continue
        frontier["_stage_gpu_num_sort"] = gpu_sort_key(gpu_num)
        pieces.append(frontier)
    if not pieces:
        return ranked.sort_values("throughput_total_tps", ascending=False).head(1).copy()

    pareto_rows = pd.concat(pieces, ignore_index=True)
    pareto_rows["_stage_tps_per_user_sort"] = pd.to_numeric(pareto_rows["tps_per_user"], errors="coerce")
    pareto_rows["_stage_throughput_sort"] = pd.to_numeric(pareto_rows["throughput_total_tps"], errors="coerce")
    pareto_rows = pareto_rows.sort_values(
        ["_stage_gpu_num_sort", "_stage_tps_per_user_sort", "_stage_throughput_sort"],
        ascending=[True, True, False],
    )
    return pareto_rows.drop(columns=["_stage_gpu_num_sort", "_stage_tps_per_user_sort", "_stage_throughput_sort"])

def gpu_sort_key(value) -> int:
        try:
            return int(value)
        except (TypeError, ValueError):
            return 0

def _strategy_config_label(row) -> str:
    if _row_has_value(row, "strategy_type"):
        return _format_config_value(row["strategy_type"]).replace("_", "+")
    modes = []
    if _row_bool(row, "pd_enabled", False):
        modes.append("pd")
    if _row_bool(row, "af_enabled", False):
        modes.append("af")
    if _row_mtp_enabled(row):
        modes.append("mtp")
    return "+".join(modes) if modes else "decode"

def _with_best_by_batch_labels(best_by_batch: pd.DataFrame) -> pd.DataFrame:
    """Attach full config and previous-point change labels to best-by-batch rows."""
    if best_by_batch.empty:
        return best_by_batch.copy()
    labeled = best_by_batch.copy().reset_index(drop=True)
    summaries = []
    changes = []
    previous = None
    for _, row in labeled.iterrows():
        summaries.append(_best_by_batch_config_summary(row))
        changes.append(
            "first best point"
            if previous is None
            else pareto_config_change_label(row, previous, fields=BEST_BY_BATCH_CHANGE_FIELDS)
        )
        previous = row
    labeled["config_summary"] = summaries
    labeled["changed_parameters"] = changes
    return labeled

def _with_explicit_batch_columns(rows: pd.DataFrame) -> pd.DataFrame:
    """Attach explicit batch columns while accepting legacy input rows."""
    if rows is None or rows.empty:
        return rows.copy() if rows is not None else pd.DataFrame()
    out = rows.copy()
    if "batch_attn_gpu" not in out.columns:
        if "batch" in out.columns:
            out["batch_attn_gpu"] = pd.to_numeric(out["batch"], errors="coerce")
        elif "Batch" in out.columns:
            out["batch_attn_gpu"] = pd.to_numeric(out["Batch"], errors="coerce")
        elif "decode_batch" in out.columns:
            out["batch_attn_gpu"] = pd.to_numeric(out["decode_batch"], errors="coerce")
        else:
            out["batch_attn_gpu"] = 1
    out["batch_attn_gpu"] = pd.to_numeric(out["batch_attn_gpu"], errors="coerce").fillna(1).clip(lower=1).astype(int)
    if "attn_dp" in out.columns:
        attn_dp = pd.to_numeric(out["attn_dp"], errors="coerce").fillna(1).clip(lower=1)
    else:
        attn_dp = pd.Series(1, index=out.index)
    if "ffn_dp" in out.columns:
        ffn_dp = pd.to_numeric(out["ffn_dp"], errors="coerce").fillna(1).clip(lower=1)
    else:
        ffn_dp = pd.Series(1, index=out.index)
    if "total_machine_batch" not in out.columns:
        out["total_machine_batch"] = (out["batch_attn_gpu"] * attn_dp).astype(int)
    else:
        out["total_machine_batch"] = pd.to_numeric(out["total_machine_batch"], errors="coerce").fillna(
            out["batch_attn_gpu"] * attn_dp
        ).clip(lower=1).astype(int)
    if "batch_ffn_gpu" not in out.columns:
        out["batch_ffn_gpu"] = [
            _ceil_div_int(total, dp) for total, dp in zip(out["total_machine_batch"], ffn_dp)
        ]
    else:
        out["batch_ffn_gpu"] = pd.to_numeric(out["batch_ffn_gpu"], errors="coerce").fillna(
            pd.Series([_ceil_div_int(total, dp) for total, dp in zip(out["total_machine_batch"], ffn_dp)], index=out.index)
        ).clip(lower=1).astype(int)
    if "decode_batch_attn_gpu" not in out.columns and "decode_batch" in out.columns:
        out["decode_batch_attn_gpu"] = pd.to_numeric(out["decode_batch"], errors="coerce").fillna(
            out["batch_attn_gpu"]
        ).astype(int)
    if "prefill_batch_attn_gpu" not in out.columns and "prefill_batch" in out.columns:
        out["prefill_batch_attn_gpu"] = pd.to_numeric(out["prefill_batch"], errors="coerce").fillna(0).astype(int)
    return out

def _without_legacy_batch_column(rows: pd.DataFrame) -> pd.DataFrame:
    """Remove ambiguous legacy batch fields from exported analysis rows."""
    if rows is None or rows.empty:
        return rows
    legacy_columns = [column for column in ("batch", "Batch", "prefill_batch", "decode_batch") if column in rows.columns]
    if not legacy_columns:
        return rows
    return rows.drop(columns=legacy_columns)

def compute_pareto_frontiers_by_gpu(
    df: pd.DataFrame,
    x_col: str = "tps_per_user",
    y_col: str = "tps_per_gpu",
) -> dict[str, dict]:
    """Compute a Pareto frontier and summary independently for each GPU count."""
    grouped = {}
    if df.empty or "gpu_num" not in df.columns:
        return grouped

    for gpu_num, group in df.groupby("gpu_num"):
        frontier = compute_pareto_frontier(group, x_col=x_col, y_col=y_col)
        summary = {
            "gpu_num": int(gpu_num),
            "point_count": int(len(group)),
            "frontier_count": int(len(frontier)),
            "x_metric": x_col,
            "y_metric": y_col,
            "best_tps_per_user": int(group[x_col].max()),
            "best_y_metric": int(group[y_col].max()),
        }
        if "tps_per_gpu" in group.columns:
            summary["best_tps_per_gpu"] = int(group["tps_per_gpu"].max())
        if "throughput_total_tps" in group.columns:
            summary["best_throughput_total_tps"] = int(group["throughput_total_tps"].max())

        grouped[str(int(gpu_num))] = {
            "summary": {
                **summary,
            },
            "frontier": frontier,
            "frontier_deltas": pareto_parameter_deltas(frontier),
        }
    return grouped

def decode_kv_cache_bytes_per_batch(model_args: ModelArgs, decode_layers: pd.DataFrame | None = None) -> float:
    """Return the per-batch decode KV-cache bytes before context-parallel sharding."""
    graph_elements = _decode_kv_cache_elements_from_layers(model_args, decode_layers)
    if graph_elements > 0:
        return graph_elements * _decode_kv_cache_bpe(model_args)

    return _decode_kv_cache_fallback_elements(model_args) * _decode_kv_cache_bpe(model_args)

def decode_kv_cache_size_bytes(
    model_args: ModelArgs,
    gpu_config: dict,
    batch_size: int,
    decode_layers: pd.DataFrame | None = None,
) -> float:
    """Return per-GPU decode KV-cache bytes after context-parallel sharding."""
    attn_cp = _positive_int(gpu_config.get("attn_cp", gpu_config.get("attn_ep", 1)), 1)
    tp_shard = _decode_kv_cache_tp_shard_factor(model_args, gpu_config, decode_layers)
    return decode_kv_cache_bytes_per_batch(model_args, decode_layers) * float(batch_size) * tp_shard / float(attn_cp)

def filter_sys_maps_by_model_limits(
    sys_maps: list[dict],
    model_args: ModelArgs,
    allow_over_routed_ffn_ep: bool = False,
) -> list[dict]:
    """Drop strategy maps that shard FFN over more EP ranks than routed experts."""
    if allow_over_routed_ffn_ep:
        return list(sys_maps)
    routed_experts = _model_routed_expert_limit(model_args)
    if routed_experts <= 0:
        return list(sys_maps)
    return [
        gpu_config
        for gpu_config in sys_maps
        if _positive_int(gpu_config.get("ffn_ep"), 1) <= routed_experts
    ]

def filter_sys_maps_by_tp_values(
    sys_maps: list[dict],
    tp_values: list[int],
    cp_values: list[int] | None = None,
    pp_values: list[int] | None = None,
) -> list[dict]:
    """Keep candidate maps whose attention/FFN TP and attention CP are explicitly requested."""
    allowed = {int(value) for value in tp_values if int(value) > 0}
    if not allowed:
        return []
    allowed_cp = {int(value) for value in (cp_values if cp_values is not None else [1, 2, 4, 8]) if int(value) > 0}
    if not allowed_cp:
        return []
    allowed_pp = {int(value) for value in (pp_values if pp_values is not None else [1]) if int(value) > 0}
    if not allowed_pp:
        return []
    return [
        gpu_config
        for gpu_config in sys_maps
        if int(gpu_config.get("pp", 1)) in allowed_pp
        and int(gpu_config.get("attn_tp", 0)) in allowed
        and int(gpu_config.get("ffn_tp", 0)) in allowed
        and int(gpu_config.get("attn_cp", gpu_config.get("attn_ep", 1))) in allowed_cp
    ]

def generate_supported_sys_maps(gpu_name: str, gpu_num: int, pp_values: list[int] | None = None) -> list[dict]:
    """Generate candidate configurations or output rows."""
    previous_pp_values = getattr(GlobalConfig, "pp_range_list", [1])
    if pp_values is not None:
        GlobalConfig.pp_range_list = [int(value) for value in pp_values if int(value) > 0]
    try:
        with redirect_stdout(io.StringIO()):
            hw = hw_inst_from_gpu_info(gpu_name, gpu_num)
        return list(hw.sys_work_map)
    finally:
        GlobalConfig.pp_range_list = previous_pp_values

