def as_bool(value) -> bool:
        if isinstance(value, str):
            return value.strip().lower() in {"1", "true", "yes", "y"}
        return bool(value)

def optional_int(name: str, default: int = 0) -> int:
        if name not in values or pd.isna(values[name]):
            return default
        return int(values[name])

def pareto_config_change_label(current, previous=None, fields=PARETO_CONFIG_FIELDS) -> str:
    """Return a compact label for one Pareto frontier point or transition."""
    current = _normalize_config_row_for_labels(current)
    previous = _normalize_config_row_for_labels(previous)
    if previous is None:
        return _compact_config_summary(current)
    changes = []
    for key, label in fields:
        if not _row_has_value(current, key) and not _row_has_value(previous, key):
            continue
        current_value = current[key] if key in current else ""
        previous_value = previous[key] if key in previous else ""
        if _format_config_value(current_value) != _format_config_value(previous_value):
            changes.append(f"{label}: {_format_config_value(previous_value)} -> {_format_config_value(current_value)}")
    return "; ".join(changes) if changes else "same parameters"

def pareto_parameter_deltas(frontier: pd.DataFrame) -> list[dict]:
    """Describe which strategy parameters change between adjacent frontier points."""
    deltas = []
    previous = None
    rows = _with_explicit_batch_columns(frontier) if _frame_has_batch_input(frontier) else frontier.copy()
    for order, row in rows.reset_index(drop=True).iterrows():
        if previous is None:
            changed_text = "frontier start"
        else:
            changed_text = pareto_config_change_label(row, previous)

        deltas.append(
            {
                "frontier_order": int(order) + 1,
                "changed_parameters": changed_text,
                "frontier_label": pareto_config_change_label(row, previous),
                "delta_tps_per_user": None if previous is None else row["tps_per_user"] - previous["tps_per_user"],
                "delta_tps_per_gpu": None if previous is None else row["tps_per_gpu"] - previous["tps_per_gpu"],
                "delta_total_throughput": None
                if previous is None or "throughput_total_tps" not in rows.columns
                else row["throughput_total_tps"] - previous["throughput_total_tps"],
            }
        )
        previous = row
    return deltas

def parse_int_list(value: str) -> list[int]:
    """Parse user input or CLI text into structured values."""
    values: list[int] = []
    seen: set[int] = set()
    for item in str(value).split(","):
        token = item.strip()
        if not token:
            continue
        if ".." in token:
            start_text, end_text = token.split("..", 1)
            start = int(start_text.strip())
            end = int(end_text.strip())
            step = 1 if end >= start else -1
            expanded = range(start, end + step, step)
        else:
            expanded = [int(token)]
        for number in expanded:
            if number not in seen:
                values.append(number)
                seen.add(number)
    return values

def parse_stage_list(value: str) -> list[int]:
    """Parse user input or CLI text into structured values."""
    value = value.strip()
    if ".." in value:
        start, end = value.split("..", 1)
        return list(range(int(start), int(end) + 1))
    return parse_int_list(value)

def pd_prefill_gpu_count(total_gpu_num: int, fraction: float = 1 / 9, alignment: int = 8) -> int:
    """Return the capped PD prefill GPU count, or 0 if no aligned count fits."""
    total = int(total_gpu_num)
    if total <= 1:
        return 0
    align = max(int(alignment), 1)
    limit = max(total * float(fraction), 0.0)
    target = int(math.floor(limit / align) * align)
    if target <= 0:
        return 0
    return min(target, total - 1)

def resolve_gpu_name(name: str) -> str:
    """Resolve user-facing GPU aliases into gpu_info.xlsx column names."""
    raw = str(name).strip()
    if not raw:
        raise ValueError("GPU name must be non-empty")
    alias = raw.lower()
    return GPU_ALIASES.get(alias, raw)

def load_state() -> Dict[str, Any]:
    """Load persisted input data for this workflow."""
    if not os.path.exists(_STATE_FILE):
        print("task_state.json not found. No tasks have been recorded yet.")
        return {}
    try:
        with open(_STATE_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            return data
    except Exception as e:
        print(f"Failed to read task_state.json: {e}")
    return {}

def main() -> None:
    """CLI entry point for this module."""
    state = load_state()
    if not state:
        return

    counter: Counter = Counter()
    for task_id, entry in state.items():
        if isinstance(entry, dict):
            status = entry.get("status", "unknown")
        else:
            status = str(entry)
        counter[status] += 1

    total = sum(counter.values())
    print("Task status summary (total: {}):".format(total))
    for status in ["pending", "running", "done", "failed"]:
        if status in counter:
            print(f"  {status:7s}: {counter[status]}")
    # Print any unexpected statuses as well
    others = {k: v for k, v in counter.items() if k not in {"pending", "running", "done", "failed"}}
    if others:
        print("  other   :")
        for k, v in others.items():
            print(f"    {k}: {v}")

def _append_progress(path: Path, event: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    payload = {"time": datetime.now().isoformat(timespec="seconds"), **event}
    with path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(payload, ensure_ascii=True) + "\n")

def discover_nvidia_hardware(gpu_info_path: Path, *, include_lpx: bool = False) -> list[str]:
    with gpu_info_path.open(newline="", encoding="utf-8") as handle:
        rows = list(csv.reader(handle))
    if not rows:
        return []

    header = rows[0]
    companies = next((row for row in rows[1:] if row and row[0].strip().lower() == "companies"), [])
    hardware = []
    for index, name in enumerate(header[1:], start=1):
        clean_name = name.strip()
        if not clean_name or clean_name == "unit" or clean_name.lower().startswith("unnamed:"):
            continue
        company = companies[index].strip().lower() if index < len(companies) else ""
        if company != "nvidia":
            continue
        if not include_lpx and "lpx" in clean_name.lower():
            continue
        hardware.append(clean_name)
    return hardware

def discover_workbook_cases(workbook_dir: Path) -> list[WorkbookCase]:
    cases = []
    for workbook in sorted(workbook_dir.glob("*.xlsx")):
        try:
            cases.append(parse_workbook_case(workbook))
        except ValueError:
            continue
    return cases

def _bool_series(values: pd.Series) -> pd.Series:
    if values.dtype == bool:
        return values.fillna(False)
    return values.fillna(False).astype(str).str.strip().str.lower().isin({"1", "true", "yes", "y"})

def _positive_int(value, default: int = 1) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    return parsed if parsed > 0 else default

def _read_prefill_rows(web_data_dir: Path) -> pd.DataFrame | None:
    path = web_data_dir / "final_prefill_all.xlsx"
    if not path.exists():
        return None
    return pd.read_excel(path)

def _run_tasks(workbook: Path, tasks: list[tuple], workers: int, label: str) -> list[dict]:
    rows = []
    if not tasks:
        return rows
    if workers <= 1:
        model_args = load_model_args(workbook)
        base_decode = load_decode_layers(workbook)
        for index, task in enumerate(tasks, start=1):
            row = run_decode_strategy(base_decode, model_args, *task)
            if row is not None:
                rows.append(row)
            if index == len(tasks) or index % 25 == 0:
                print(f"{label} {index}/{len(tasks)} rows={len(rows)}", flush=True)
        return rows

    with concurrent.futures.ProcessPoolExecutor(
        max_workers=workers,
        initializer=init_worker,
        initargs=(str(workbook),),
    ) as executor:
        for index, row in enumerate(executor.map(run_decode_strategy_worker, tasks, chunksize=1), start=1):
            if row is not None:
                rows.append(row)
            if index == len(tasks) or index % 25 == 0:
                print(f"{label} {index}/{len(tasks)} rows={len(rows)}", flush=True)
    return rows

def select_mtp_seed_rows(decode_rows: pd.DataFrame, *, gpu_num: int, seed_count: int) -> pd.DataFrame:
    """Pick representative 72-GPU baseline rows for the expensive native MTP replay."""
    if decode_rows is None or decode_rows.empty or seed_count <= 0:
        return pd.DataFrame()
    rows = decode_rows.copy()
    rows = rows[pd.to_numeric(rows.get("gpu_num"), errors="coerce") == int(gpu_num)]
    if "mtp_on" in rows.columns:
        rows = rows[~_bool_series(rows["mtp_on"])]
    if rows.empty:
        return rows

    rows["tps_per_user"] = pd.to_numeric(rows.get("tps_per_user", 0.0), errors="coerce").fillna(0.0)
    rows["throughput_total_tps"] = pd.to_numeric(rows.get("throughput_total_tps", 0.0), errors="coerce").fillna(0.0)
    pieces = [
        rows.sort_values(["tps_per_user", "throughput_total_tps"], ascending=False).head(seed_count),
        rows.sort_values(["throughput_total_tps", "tps_per_user"], ascending=False).head(seed_count),
    ]
    if "ffn_ep" in rows.columns:
        ep_top = (
            rows.sort_values(["ffn_ep", "tps_per_user", "throughput_total_tps"], ascending=[True, False, False])
            .groupby("ffn_ep", as_index=False)
            .head(1)
        )
        pieces.append(ep_top)

    selected = pd.concat(pieces, ignore_index=True)
    selected["_config_key"] = selected.apply(_row_config_key, axis=1)
    selected = selected.drop_duplicates("_config_key")
    selected = selected.sort_values(["tps_per_user", "throughput_total_tps"], ascending=False)
    return selected.drop(columns=["_config_key"]).head(seed_count).reset_index(drop=True)
